<?php

namespace Database\Seeders;

use App\Models\Activity;
use Illuminate\Database\Seeder;

/**
 * Preschool Tier Curriculum — 3 to 5 years
 * Target: ~400 activities across 12 subjects
 * Content policy: No instrumental music. No problematic IP. Halal content only.
 * Islamic subjects (quran, arabic, islamic_studies) gated to Muslim households at model level.
 * is_free: first 8 per subject = true, rest = false.
 */
class PreschoolActivitySeeder extends Seeder
{
    public function run(): void
    {
        foreach (array_chunk($this->activities(), 50) as $chunk) {
            foreach ($chunk as $data) {
                Activity::updateOrCreate(
                    ['title' => $data['title']],
                    array_merge(['instructions' => $data['description'] ?? null], $data, ['language' => 'en', 'like_count' => 0])
                );
            }
        }
    }

