            ['title' => 'Penny Sorting and Counting',           'emoji' => '🪙', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on', 'skill' => 'Currency concept introduction',     'description' => 'Sort coins by appearance and count a pile of identical coins. Real-world mathematical applications (money) give children a powerful incentive to count accurately and provide authentic contexts for later subtraction problems.'],
            ['title' => 'Shape Hunt in the Home',               'emoji' => '🔷', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'observation', 'skill' => 'Geometry in the environment',       'description' => 'Walk through the home identifying real-world shapes — "The door is a rectangle, the clock is a circle, the pizza slice is a triangle." Recognising geometry in real environments transfers abstract shape knowledge to spatial reasoning in three-dimensional space.'],
            ['title' => 'Length Comparison with Strips',        'emoji' => '📐', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on', 'skill' => 'Non-standard length measurement',   'description' => 'Compare ribbon strips of different lengths — align one end and identify which is longer/shorter. Direct comparison of length (before units) builds measurement understanding and introduces the transitivity principle in a hands-on context.'],
            ['title' => 'Graph It: Favourite Fruit Bar Chart',  'emoji' => '📊', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'hands_on', 'skill' => 'Data collection and representation', 'description' => 'Survey family members about their favourite fruit and build a picture bar chart. Early data literacy — collecting, organising, and reading simple graphs — develops statistical thinking and connects mathematics to real questions about the world.'],
            ['title' => 'Halving: Sharing Equally',             'emoji' => '✂️', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on', 'skill' => 'Fraction concept: half',            'description' => 'Distribute 6 crackers equally between two plates — "3 and 3 — each person gets half." The concept of a half is the gateway fraction and should be grounded first in equal sharing of real objects before any visual fraction representation.'],
            ['title' => 'Clock Face: O\'clock Introduction',    'emoji' => '🕐', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on', 'skill' => 'Time: o\'clock reading',             'description' => 'Use a large manipulative clock to set and read o\'clock times. "The hands tell us it\'s 3 o\'clock — time for your snack!" Embedding time reading in daily routine gives numeral positions meaning and introduces the concept that numbers represent both quantity and position.'],
            ['title' => '3D Shape Exploration: Cube and Sphere', 'emoji' => '⬛', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'sensory',  'skill' => '3D geometry properties',            'description' => 'Hold, roll, and stack 3D shapes (cube, sphere, cylinder, cone) and describe their properties — "The sphere rolls; the cube has flat faces and stacks." Three-dimensional geometry is frequently undertaught; physical handling before visual representation builds genuine geometric understanding.'],
            ['title' => 'Before and After Numbers',             'emoji' => '🔢', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'game',     'skill' => 'Number sequence and adjacent numbers', 'description' => 'Show a number card and name the number that comes before and after it. "5 — what comes before? 4. What comes after? 6." Adjacent number knowledge builds flexibility of thought about number sequence and is a strong predictor of mental arithmetic speed.'],
            ['title' => 'Number Writing Practice 1–10',         'emoji' => '✏️', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'worksheet', 'skill' => 'Numeral formation',                 'description' => 'Trace then write numerals 1–10 on dotted lines, verbalising each number name. Correct numeral formation (direction, starting point) must be explicitly taught; children who learn incorrect habits early require significant time to unlearn them.'],
            ['title' => 'Sorting by Two Attributes',            'emoji' => '🔵', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'hands_on', 'skill' => 'Multi-attribute classification',    'description' => 'Sort a collection of objects by two features simultaneously — "Put all the big red shapes here." Two-attribute sorting is a Piagetian concrete operations task that develops logical classification, a prerequisite for set union and intersection concepts.'],
            ['title' => 'Tally Chart: Counting Birds Outside',  'emoji' => '🐦', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'outdoor',  'skill' => 'Tallying and data recording',        'description' => 'Sit outside and make a tally mark for each bird (or car colour) spotted over 5 minutes, then count the total tallies. Tallying introduces a recording system, the concept of counting by fives, and authentic reasons to count carefully.'],
            ['title' => 'Number Bonds to 5',                    'emoji' => '🔴', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'hands_on', 'skill' => 'Part-whole number relationships',   'description' => 'Use two-colour counters or coloured pebbles to find all combinations that make 5 (4+1, 3+2, 2+3, 1+4, 5+0). Number bonds are the foundation of mental arithmetic; children who know bonds to 5 and 10 can compute far more efficiently than those who count sequentially.'],
            ['title' => 'Mass Comparison: Heavier or Lighter',  'emoji' => '⚖️', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on', 'skill' => 'Mass comparison and vocabulary',    'description' => 'Hold an object in each hand and compare — "Which is heavier? Which is lighter?" Then check with a simple balance. Measurement vocabulary (heavier, lighter, heaviest, lightest) connected to physical experience builds the intuitive mass understanding needed before standard units.'],
            ['title' => 'Symmetry Fold Art',                    'emoji' => '🪞', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'craft',    'skill' => 'Line of symmetry concept',          'description' => 'Paint blobs on one side of a folded paper, press together, then unfold to reveal a symmetrical pattern. Symmetry — one of the most beautiful concepts in mathematics — is most powerfully understood through this hands-on fold-and-reveal action.'],
            ['title' => 'Skip Counting by 2s with Actions',     'emoji' => '🦘', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'hands_on', 'skill' => 'Skip counting: multiples of 2',     'description' => 'Jump twice then say a number: 2, 4, 6, 8, 10 — using body movement to mark each count. Skip counting by 2s is the earliest multiplication pattern and also builds the numerical fluency required for even/odd concepts and later times tables.'],
            ['title' => 'Estimation Jar',                       'emoji' => '🫙', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'game',     'skill' => 'Estimation and number benchmarks',  'description' => 'Guess how many marbles are in a jar (10–20 range) before counting to check. Estimation develops number sense and benchmarking — the ability to use reference numbers to judge "about how many" — which underpins mental arithmetic and problem solving throughout life.'],
            ['title' => 'Positional Language Obstacle Course',  'emoji' => '🗺️', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'outdoor',  'skill' => 'Spatial language and direction',    'description' => 'Navigate an obstacle course following positional directions — "Go over the cushion, under the table, between the chairs, around the box." Spatial language (over, under, between, behind) is a mathematical concept strand directly linked to later geometry and measurement understanding.'],
            ['title' => 'Counting Backwards from 10',           'emoji' => '🚀', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'game',     'skill' => 'Reverse number sequence',           'description' => 'Count down "10, 9, 8, 7… 1, Blast off!" with a launch at the end. Backward counting builds number sequence flexibility and is also the conceptual foundation of subtraction — counting back requires holding the sequence as a reversible structure.'],

            // ═══════════════════════════════════════════════════════
            // MATH — batch 3 of 3 (activities 31–45)
            // ═══════════════════════════════════════════════════════
            ['title' => 'Number Bonds to 10',                   'emoji' => '🔟', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'hands_on', 'skill' => 'Addition to 10',                    'description' => 'Use fingers, blocks, or two-colour counters to find all pairs that sum to 10 (1+9, 2+8…). Number bonds to 10 are the most important early arithmetic facts; children who automatise these have a permanent mental arithmetic advantage over peers who do not.'],
            ['title' => 'Temperature: Hot and Cold Exploration',  'emoji' => '🌡️', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'sensory',  'skill' => 'Measurement: temperature vocabulary', 'description' => 'Feel objects that are warm, cool, and at room temperature and order them. Introducing measurement as "describing properties of objects" before using units builds deep conceptual understanding across all measurement strands.'],
            ['title' => 'Capacity Pouring: Full and Empty',      'emoji' => '🚿', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'sensory',  'skill' => 'Capacity and volume language',       'description' => 'Pour water between containers of different sizes and describe them as full, half-full, and empty. Capacity vocabulary grounded in physical play prevents the persistent misconception that taller containers are always larger.'],
            ['title' => 'Repeating Pattern: Make Your Own',      'emoji' => '🔁', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'creative',  'skill' => 'Pattern creation and generalisation', 'description' => 'Create your own repeating pattern using beads, blocks, or stickers, then describe the rule aloud. Articulating the pattern rule builds algebraic reasoning — moving from recognising patterns to generating and verbalising the underlying structure.'],
            ['title' => 'Days of the Week Sequence',             'emoji' => '📅', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'routine',  'skill' => 'Temporal sequence and calendar',     'description' => 'Each morning, say and show the day of the week on a calendar chart. "Yesterday was Monday. Today is Tuesday. Tomorrow will be Wednesday." Temporal sequencing (days, weeks, months) is a foundational mathematical topic that also supports sentence grammar and narrative comprehension.'],
            ['title' => 'ABAB Pattern with Body Percussion',     'emoji' => '🥁', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'hands_on', 'skill' => 'Rhythmic patterning',               'description' => 'Clap-stomp, clap-stomp, clap-stomp in a steady ABAB pattern. Rhythmic patterns (a cappella) connect mathematical pattern concepts to music cognition and kinesthetic memory, making the abstract concrete.'],
            ['title' => 'Greater Than and Less Than',            'emoji' => '⬅️', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'game',     'skill' => 'Number comparison and inequality',  'description' => 'Compare two dot cards and place the hungry crocodile mouth symbol between them — "4 is greater than 2, the mouth eats the bigger number!" The iconic greater-than/less-than comparison is the symbolic precursor to all inequality notation in later maths.'],
            ['title' => 'Measuring Height with a Growth Chart',  'emoji' => '📏', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'routine',  'skill' => 'Measurement: personal relevance',   'description' => 'Mark height on a wall chart monthly and compare to previous marks. Personal growth measurement makes abstract measurement concepts directly relevant; children also begin to develop the concept that change can be measured and tracked over time.'],
            ['title' => 'Geometry: Tangram Puzzle (4 pieces)',   'emoji' => '🟧', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'hands_on', 'skill' => 'Spatial rotation and composition',  'description' => 'Arrange 4 tangram pieces to fill a simple outline (house, fish, bird). Spatial composition — building shapes from smaller shapes — develops the geometric reasoning and mental rotation skills essential for later geometry and STEM disciplines.'],
            ['title' => 'Doubles: Mirror Addition Game',         'emoji' => '🪩', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'game',     'skill' => 'Doubles facts to 10',               'description' => 'Place equal towers of blocks on each side of a mirror and count the total — "3 and 3 is double 3 = 6!" Doubles facts are among the first arithmetic facts children memorise and serve as anchor points for all "near doubles" mental calculation strategies.'],
            ['title' => 'Story Problem: Maths in Context',       'emoji' => '📖', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'discussion', 'skill' => 'Problem solving with context',      'description' => 'Listen to a simple story problem ("Fatima had 3 dates. Her brother gave her 2 more. How many dates?") and solve it with objects. Story problems connect abstract arithmetic to real situations — the first step toward mathematical modelling.'],
            ['title' => 'Money: Recognising Coins',              'emoji' => '💰', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on', 'skill' => 'Currency recognition',              'description' => 'Sort a range of coins by appearance, naming each denomination. Real money is one of the most motivating mathematical contexts for young children, and early currency recognition connects number learning directly to community participation.'],
            ['title' => 'Counting to 20',                       'emoji' => '2️⃣', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'hands_on', 'skill' => 'Number sequence beyond 10',         'description' => 'Count a collection of 20 objects by placing them in a line or rows of 10 and counting accurately to 20. Extending counting to 20 with objects builds the place-value intuition of tens and ones before formal notation is introduced.'],
            ['title' => 'Number Ordering: Arrange 1–10',         'emoji' => '🔢', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on', 'skill' => 'Number ordering and sequence',      'description' => 'Shuffle number cards 1–10 and arrange them in correct sequence. Number ordering consolidates sequence knowledge, introduces the language of "between" (5 is between 4 and 6), and prepares children for the mental number line that underpins all mental arithmetic.'],
            ['title' => 'Data Pictograph: Our Birthdays',        'emoji' => '🎂', 'age_tier' => 'preschool', 'subject' => 'math', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'hands_on', 'skill' => 'Pictograph reading and creation',   'description' => 'Place birthday cake pictures in month columns on a chart and read which month has the most/fewest birthdays. Reading pictographs integrates counting, comparison, and data literacy — a curriculum expectation at Year 1 that is most powerfully built through personally meaningful contexts.'],

            // ═══════════════════════════════════════════════════════
            // SCIENCE — batch 1 of 2 (activities 1–10)
            // ═══════════════════════════════════════════════════════
            ['title' => 'Sink or Float Investigation',           'emoji' => '🛶', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 20, 'activity_type' => 'experiment', 'skill' => 'Scientific prediction and testing', 'description' => 'Predict whether each object will sink or float, then test in a water basin and record the result. This classic experiment introduces the full scientific method — predict, test, observe, conclude — in a hands-on context that remains engaging through dozens of repetitions.'],
            ['title' => 'Magnet Discovery Tray',                 'emoji' => '🧲', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 15, 'activity_type' => 'experiment', 'skill' => 'Property investigation: magnetism', 'description' => 'Test a range of objects with a magnet and sort them into "attracted" and "not attracted" groups. Magnetism experiments powerfully demonstrate that invisible forces exist and that materials have properties that are not always visible — foundational concepts in physical science.'],
            ['title' => 'Rain Cloud in a Jar',                   'emoji' => '🌧️', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 15, 'activity_type' => 'experiment', 'skill' => 'Water cycle: condensation concept', 'description' => 'Add blue food-coloured water droplets to shaving foam floating on water in a jar; watch "rain" fall through the foam. This visual model of cloud saturation and precipitation makes the water cycle tangible and memorable.'],
            ['title' => 'Plant Seed Germination Journal',        'emoji' => '🌱', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 10, 'activity_type' => 'observation', 'skill' => 'Life cycle observation and recording', 'description' => 'Plant a fast-germinating seed (bean, cress) in a clear container and draw what you see daily. Seed germination is the most accessible life science starting point; drawing observations every day builds scientific record-keeping habits from preschool.'],
            ['title' => 'Shadow Tracing on the Ground',          'emoji' => '☀️', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 15, 'activity_type' => 'outdoor',   'skill' => 'Light and shadow science',          'description' => 'Stand outside in sunshine, trace your shadow in chalk, then return an hour later and trace it again. Observing shadow length and direction change is a direct hands-on experience of Earth\'s rotation — the most fundamental astronomy concept.'],
            ['title' => 'Ice Melting Race',                      'emoji' => '🧊', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 20, 'activity_type' => 'experiment', 'skill' => 'State of matter: solid to liquid',  'description' => 'Place identical ice cubes in different locations (sun, shade, wrapped in cloth) and observe which melts first. This experiment develops understanding of matter changing state, the effect of temperature, and the concept of a fair test.'],
            ['title' => 'Colour Mixing: Primary to Secondary',   'emoji' => '🎨', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 15, 'activity_type' => 'experiment', 'skill' => 'Light and colour: mixing',          'description' => 'Mix two primary-colour paints to discover secondary colours — "Red and blue make purple!" The transformative discovery that mixing creates entirely new colours is one of preschool\'s most iconic science moments and introduces the concept that matter combines to form new matter.'],
            ['title' => 'Weather Journal: Daily Observations',   'emoji' => '🌤️', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 8,  'activity_type' => 'observation', 'skill' => 'Meteorological observation skills', 'description' => 'Check the sky each morning, describe the weather, and add a symbol to a daily weather chart. Daily weather observation builds scientific observation habits, pattern recognition over time, and the vocabulary of meteorology.'],
            ['title' => 'Animal Habitat Match',                  'emoji' => '🦁', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'hands_on',  'skill' => 'Ecosystems: animal-habitat relationships', 'description' => 'Match animal picture cards to their habitat cards — fish to ocean, bear to forest, camel to desert. Animal-habitat relationships introduce ecological science (the science of how living things relate to their environments) in a concrete, memorable card-matching format.'],
            ['title' => 'Five Senses Investigation Walk',        'emoji' => '👃', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 20, 'activity_type' => 'outdoor',   'skill' => 'Systematic sensory observation',   'description' => 'Walk outdoors using all five senses in sequence — find something to see, smell, hear, touch, and (safely) taste. Systematic multi-sensory observation trains the scientific habit of using all available evidence, not just vision, when investigating a phenomenon.'],

            // ═══════════════════════════════════════════════════════
            // SCIENCE — batch 2 of 2 (activities 11–35)
            // ═══════════════════════════════════════════════════════
            ['title' => 'Vinegar and Baking Soda Volcano',      'emoji' => '🌋', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 20, 'activity_type' => 'experiment', 'skill' => 'Chemical reactions: observable changes', 'description' => 'Add vinegar to a baking soda mound and watch the fizzing reaction. This classic experiment demonstrates a chemical change — new substances (gas, water) are produced that were not present before — providing a dramatic, memorable introduction to chemistry.'],
            ['title' => 'Human Body Parts Labelling',            'emoji' => '🧍', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'hands_on',  'skill' => 'Anatomy: external body parts',     'description' => 'Trace your body outline on paper and label the main external parts with drawn or written labels. Understanding the human body is one of children\'s most intrinsically motivated science topics and builds the anatomy vocabulary needed for health education.'],
            ['title' => 'Life Cycle: Butterfly Sequence Cards', 'emoji' => '🦋', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'hands_on',  'skill' => 'Life cycle sequencing',            'description' => 'Arrange butterfly life cycle cards (egg → caterpillar → chrysalis → butterfly) in order and narrate each stage. Life cycle sequencing integrates biology, chronological sequence thinking, and vocabulary development in one rich conceptual activity.'],
            ['title' => 'What Do Plants Need? Experiment',       'emoji' => '🌿', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'experiment', 'skill' => 'Plant biology: needs and growth',  'description' => 'Grow two identical seeds — one in a sunny spot with water, one in a dark cupboard without. Compare after a week. This fair test introduces the concept of controlled variables and demonstrates that plants need light and water — a foundational life science understanding.'],
            ['title' => 'Food Sorting: Healthy vs Treat',        'emoji' => '🥕', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on',  'skill' => 'Nutrition classification',         'description' => 'Sort food picture cards into "eat lots" and "eat sometimes" groups. Early nutrition education builds health habits most effectively when framed positively and concretely — classifying familiar foods is far more effective than abstract rule-learning.'],
            ['title' => 'Material Properties Sorting',           'emoji' => '🔩', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'hands_on',  'skill' => 'Physical science: material properties', 'description' => 'Sort objects by their material (wood, metal, plastic, fabric) and describe why each material is used for a given purpose. Understanding that materials are chosen for their properties is a core physical science concept that connects science to design and engineering thinking.'],
            ['title' => 'Rain Gauge: Observing Rainfall',        'emoji' => '🌧️', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'observation', 'skill' => 'Measurement in science',           'description' => 'Place a marked container outside during rain and read the water level afterwards. Building a simple rain gauge introduces measurement in a scientific context and teaches that weather phenomena can be quantified and compared over time.'],
            ['title' => 'Insect Hunt and Record',                'emoji' => '🐛', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 20, 'activity_type' => 'outdoor',   'skill' => 'Biodiversity and classification',  'description' => 'Search the garden or outdoor area for insects and draw or tally each type found. Direct contact with living organisms builds respect for nature alongside scientific classification skills, and outdoor science is consistently linked to greater environmental stewardship in later life.'],
            ['title' => 'Dissolving: Sugar, Salt, Sand Test',    'emoji' => '🧪', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'experiment', 'skill' => 'Properties of matter: solubility', 'description' => 'Stir sugar, salt, and sand into separate cups of water and observe which dissolves. This experiment introduces the concept that different substances have different solubility — and that science involves observing differences between seemingly similar processes.'],
            ['title' => 'Sound Vibration: Feel the Buzz',        'emoji' => '🔊', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'experiment', 'skill' => 'Physics: sound as vibration',      'description' => 'Hum with fingers touching your throat and feel the vibration. Tap a drum or pluck a rubber band stretched between fingers and feel the buzz. Demonstrating that sound IS vibration — not just something you hear — is the foundational physics concept behind all acoustics.'],
            ['title' => 'Float a Boat: Paper Engineering',       'emoji' => '⛵', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 20, 'activity_type' => 'experiment', 'skill' => 'Buoyancy and basic engineering',   'description' => 'Fold a simple paper or foil boat and test how many pennies it holds before sinking. This combines science (buoyancy, displacement) with engineering design thinking — iterating to make the strongest boat — in a naturally compelling challenge.'],
            ['title' => 'Worm Farm Observation',                 'emoji' => '🪱', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'observation', 'skill' => 'Biology: decomposers and soil',    'description' => 'Set up a simple worm observation container with soil and food scraps, and observe the worms burrowing and composting. Worm study introduces decomposition, the food chain, and the role of organisms in soil health — rich biology concepts accessible at preschool.'],
            ['title' => 'Day and Night: Causes and Cycles',      'emoji' => '🌙', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'hands_on',  'skill' => 'Earth science: rotation and light', 'description' => 'Use a torch (sun) and a globe or ball (Earth) to show how Earth\'s rotation creates day and night. This simple model makes an abstract astronomical concept concrete and directly accessible to 4-year-olds, building their mental model of the solar system.'],
            ['title' => 'Seasons Photo Sort',                    'emoji' => '🍂', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on',  'skill' => 'Earth science: seasonal change',  'description' => 'Sort photographs of outdoor scenes into the four seasons and describe the identifying features — "Autumn: leaves are orange and falling." Seasonal classification builds observational comparison skills, temporal pattern recognition, and vocabulary across all four seasons.'],
            ['title' => 'Forces: Push and Pull Exploration',     'emoji' => '👊', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'hands_on',  'skill' => 'Physics: forces vocabulary',      'description' => 'Identify everyday push and pull forces — pushing open a door, pulling a drawer, pushing a ball. Labelling forces (push/pull) introduces the key vocabulary of physics and the concept that all movement is caused by a force — Newton\'s first law in child-accessible language.'],
            ['title' => 'Rock Sorting by Observable Properties', 'emoji' => '🪨', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'hands_on',  'skill' => 'Earth science: rock properties',  'description' => 'Collect rocks outdoors and sort them by colour, texture (rough/smooth), and size. Geoscience begins with observable properties of rocks and minerals; the act of sorting by attribute trains scientific classification while building connection to the natural world.'],
            ['title' => 'Air Power: Balloon Rocket',             'emoji' => '🎈', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'experiment', 'skill' => 'Physics: air pressure and thrust', 'description' => 'Thread a balloon on string and release to watch it zoom forward. This dramatic experiment demonstrates that air is a gas with mass and pressure — and introduces Newton\'s third law (action-reaction) in the most visually compelling and testable way possible for preschoolers.'],
            ['title' => 'Leaf Rubbing Nature Art',               'emoji' => '🍃', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'craft',      'skill' => 'Plant structures: leaf patterns', 'description' => 'Place leaves under paper and rub crayons across the surface to reveal vein patterns, then compare leaves from different plants. Leaf rubbing reveals the internal transport structures of plants and makes microscopic anatomy visible — bridging art and science.'],
            ['title' => 'Liquid Density Tower',                  'emoji' => '🧃', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'experiment', 'skill' => 'Physics: density concept',        'description' => 'Layer honey, water, and cooking oil in a clear cylinder and observe they separate into distinct layers. This elegant experiment demonstrates density — that equal volumes of different liquids have different masses — in a visual, hands-on way.'],
            ['title' => 'Simple Machine: Lever and Fulcrum',     'emoji' => '⚖️', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'experiment', 'skill' => 'Engineering: lever mechanics',     'description' => 'Balance a ruler over a pencil and feel how the position of the pivot changes the force needed to lift a weight. Lever mechanics are the simplest introduction to engineering and mechanical advantage — and powerfully connect physics to real tools like see-saws and spoons.'],
            ['title' => 'Static Electricity: Balloon Sticking',  'emoji' => '⚡', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'experiment', 'skill' => 'Physics: static charge',          'description' => 'Rub a balloon on your hair and stick it to the wall, then use it to move small paper pieces without touching. Static electricity is one of the most magical-seeming but entirely explainable phenomena in physics — making it a powerful hook for scientific curiosity.'],
            ['title' => 'Nature Colour Mixing: Plants as Ink',   'emoji' => '🌺', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 20, 'activity_type' => 'experiment', 'skill' => 'Chemistry: natural pigments',      'description' => 'Crush berries, turmeric, and spinach leaves in separate pots as natural paint. Observe the colours and compare them. Natural pigment extraction introduces chemistry (colour compounds), biology (plant chemistry), and art-science integration in one rich activity.'],
            ['title' => 'Gravity Drop Test',                     'emoji' => '⬇️', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'experiment', 'skill' => 'Physics: gravity',                'description' => 'Drop a heavy and a light object simultaneously from the same height and observe they land together. This reproduction of Galileo\'s experiment dismantles the intuitive misconception that heavy things fall faster, building the habit of testing intuitions with experiments.'],
            ['title' => 'Body Movement and Exercise Science',    'emoji' => '🏃', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'experiment', 'skill' => 'Human biology: heart and exercise', 'description' => 'Feel your heartbeat at rest, run for one minute, then feel it again. Count the difference. This simple experiment connects physical science (measurement) to biology (circulatory system) and health education in one embodied investigation.'],
            ['title' => 'Water Absorption Sponge vs Stone',      'emoji' => '🧽', 'age_tier' => 'preschool', 'subject' => 'science', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'experiment', 'skill' => 'Material science: porosity',       'description' => 'Dip a sponge and a stone in water and weigh (or squeeze) both before and after. Observing that porous materials absorb water while non-porous ones do not introduces material science concepts directly relevant to engineering applications like drainage and insulation.'],

