            ['title' => 'Free Drawing with Crayons',             'emoji' => '🖍️', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 15, 'activity_type' => 'craft',       'skill' => 'Creative self-expression',         'description' => 'Draw anything you like on blank paper with chunky crayons. Unstructured, child-directed drawing is the foundation of artistic identity, fine motor control, and visual communication — and should make up the majority of art time in early childhood.'],
            ['title' => 'Easel Watercolour Painting',            'emoji' => '🎨', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 20, 'activity_type' => 'craft',       'skill' => 'Brush control and colour mixing',  'description' => 'Paint at an easel using watercolours, working on large paper from shoulder height. Vertical surface painting activates core body stabilisation and develops the same shoulder-to-wrist movement chain that later controls writing — while exploring colour and fluidity.'],
            ['title' => 'Nature Collage: Leaves and Petals',     'emoji' => '🍀', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 20, 'activity_type' => 'craft',       'skill' => 'Composition and texture',          'description' => 'Collect leaves, petals, and twigs outdoors and arrange them into a picture glued onto card. Nature collage integrates outdoor exploration, tactile texture awareness, compositional thinking, and fine motor precision in one richly meaningful project.'],
            ['title' => 'Playdough Sculpture: Animals',          'emoji' => '🐘', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 20, 'activity_type' => 'craft',       'skill' => '3D form and spatial thinking',     'description' => 'Use playdough to sculpt an animal of your choice, adding details with tools. Three-dimensional making builds spatial reasoning, fine motor strength, and mental rotation in a medium that is endlessly malleable and error-tolerant.'],
            ['title' => 'Coloured Paper Tearing Mosaic',         'emoji' => '🌈', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 20, 'activity_type' => 'craft',       'skill' => 'Pincer control and composition',   'description' => 'Tear coloured paper into small pieces and arrange and glue them to fill a simple shape outline. Paper tearing mosaic is a Montessori classic that builds pincer strength and precision while introducing composition — how small units combine to create a whole image.'],
            ['title' => 'Pattern Printing with Vegetables',      'emoji' => '🥦', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 15, 'activity_type' => 'craft',       'skill' => 'Pattern making and shape printing', 'description' => 'Dip cut vegetables (celery, potato, bell pepper) in paint and stamp a repeating pattern. Vegetable printing reveals the hidden geometry of food cross-sections while building patterning concepts, stamping precision, and understanding of symmetry.'],
            ['title' => 'Self Portrait Drawing',                 'emoji' => '🪞', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 15, 'activity_type' => 'craft',       'skill' => 'Observational art and self-concept', 'description' => 'Look in a mirror and draw yourself, including all the features you see. Self-portraiture integrates observation, fine motor control, and a child\'s developing sense of personal identity. Comparing self-portraits over time shows remarkable cognitive and artistic development.'],
            ['title' => 'Bubble Wrap Texture Printing',          'emoji' => '💠', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 15, 'activity_type' => 'craft',       'skill' => 'Printmaking and texture transfer',  'description' => 'Roll paint onto bubble wrap and press it onto paper to transfer the circular texture. Printmaking introduces the concept that surfaces can be used as tools to transfer marks — a different understanding of image-making than direct drawing or painting.'],
            ['title' => 'Straw Blowing Art',                     'emoji' => '💨', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'craft',       'skill' => 'Controlled breath and oral motor',  'description' => 'Drop paint blobs on paper and use a straw to blow them into flowing tree-branch shapes. Straw blowing art develops controlled breath, oral motor skills, and directionality of mark-making — while producing organically beautiful, unpredictable artwork.'],
            ['title' => 'Geometric Shape Collage',               'emoji' => '🔶', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 20, 'activity_type' => 'craft',       'skill' => 'Shape composition and spatial play', 'description' => 'Cut and arrange pre-cut geometric shapes (triangles, squares, circles) to build pictures — a house from rectangles and triangles, a robot from squares. Shape composition is both an art and mathematics activity and develops the spatial reasoning underlying later geometry.'],
            ['title' => 'Oil Pastel Drawing on Dark Paper',      'emoji' => '🌑', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 18, 'activity_type' => 'craft',       'skill' => 'Colour vibrancy and contrast',     'description' => 'Draw with bright oil pastels on black card and observe the striking contrast. The experience of seeing vibrant colours "glow" against a dark background introduces the concept of visual contrast and how background affects foreground colour perception.'],
            ['title' => 'Clay Pinch Pot',                        'emoji' => '🏺', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 20, 'activity_type' => 'craft',       'skill' => '3D ceramics: pinch technique',     'description' => 'Use air-dry clay to form a pinch pot by pressing thumbs into a ball and pinching out the walls evenly. Pinch pot making is a foundational 3D art technique that builds thumb strength, bilateral coordination, and understanding of form, wall thickness, and structural stability.'],
            ['title' => 'Torn Tissue Paper Rainbow',             'emoji' => '🌈', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 20, 'activity_type' => 'craft',       'skill' => 'Colour spectrum sequence',         'description' => 'Tear strips of tissue paper in red, orange, yellow, green, blue, and violet to build a layered rainbow collage. This project embeds the colour spectrum sequence (ROYGBV) into a tactile art experience — rainbow ordering is a science-art bridge concept.'],
            ['title' => 'Sponge Stamp Landscape',                'emoji' => '🌄', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 20, 'activity_type' => 'craft',       'skill' => 'Landscape composition: foreground/background', 'description' => 'Sponge a blue sky and green ground, then stamp trees, clouds, and shapes to build a landscape. Landscape composition introduces foreground, middle ground, and background — the three planes of visual depth found in all representational art.'],
            ['title' => 'Weaving: Paper Strips',                 'emoji' => '🧵', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 20, 'activity_type' => 'craft',       'skill' => 'Sequential weaving pattern',       'description' => 'Weave coloured paper strips over-under-over-under through a paper loom frame. Paper weaving builds the exact bilateral coordination, pattern following, and sequential memory also required for early reading and maths — often called the "Montessori pre-reader" activity.'],
            ['title' => 'Symmetry Butterfly Print',              'emoji' => '🦋', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'craft',       'skill' => 'Symmetry in art and nature',       'description' => 'Paint one half of a butterfly outline, fold the paper and press to create a mirror image. This art activity produces a symmetrical result and allows children to see that symmetry occurs in nature — directly linking to the mathematical concept of a line of symmetry.'],
            ['title' => 'Recycled Material Sculpture',           'emoji' => '♻️', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 30, 'activity_type' => 'craft',       'skill' => 'Design thinking with constraints', 'description' => 'Build a sculpture using toilet roll tubes, boxes, and bottle caps. Junk modelling (using repurposed materials) develops design thinking under constraints — a foundational engineering mindset — while embedding sustainability values in early childhood.'],
            ['title' => 'Drawing to Music (Vocal/Nature)',        'emoji' => '🎵', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'craft',       'skill' => 'Kinaesthetic-auditory-visual link',  'description' => 'Draw freely while a cappella vocals or nature sounds play softly. Move the crayon fast with fast rhythms, slow with quiet. Music-responsive drawing integrates auditory processing, kinesthetic response, and visual output — a cross-modal creative experience.'],
            ['title' => 'Portrait of a Family Member',           'emoji' => '👨‍👩‍👧', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'craft',       'skill' => 'Observational portrait composition', 'description' => 'Draw a portrait of a family member from life, trying to include all their features. Drawing people from observation develops sustained visual attention, face processing, and the concept of likeness — all while strengthening the child\'s family bonds and emotional intelligence.'],
            ['title' => 'Nature Mandala (Outdoor)',               'emoji' => '🌸', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 20, 'activity_type' => 'outdoor',     'skill' => 'Radial symmetry and pattern',      'description' => 'Arrange collected natural objects (pebbles, leaves, flowers) in a circular, symmetrical mandala on the ground. Natural art requires no materials beyond nature itself, and the radial symmetry of a mandala introduces rotational symmetry — a concept encountered formally in secondary geometry.'],
            ['title' => 'Ink Blot Imagination',                  'emoji' => '🖤', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'craft',       'skill' => 'Imaginative seeing and divergent thinking', 'description' => 'Drop ink or paint to create random blots, then rotate the paper and describe what you see — "I see a bear! I see a cloud!" Rorschach-style image interpretation develops divergent thinking, imaginative flexibility, and the ability to see multiple interpretations in a single image.'],
            ['title' => 'Cutting Along Lines: Skill Practice',   'emoji' => '✂️', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'hands_on',    'skill' => 'Scissor control and bimanual coordination', 'description' => 'Cut along thick-printed straight and curved lines, then cut out simple shapes. Scissor skills require both hands to work differently and simultaneously — a demanding bimanual coordination task that directly prepares the hands for pen and pencil precision.'],
            ['title' => 'Drawing from Observation: Fruit',       'emoji' => '🍎', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'craft',       'skill' => 'Still life and observation drawing', 'description' => 'Place one piece of fruit on the table and draw it carefully, looking back and forth between the fruit and your paper. Observational still-life drawing trains focused visual attention and hand-eye coordination at a level far more advanced than drawing from memory.'],
            ['title' => 'Geometric Pattern Islamic Tile Coloring', 'emoji' => '🕌', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'craft',       'skill' => 'Islamic art heritage and pattern',  'description' => 'Colour a simple pre-drawn geometric pattern inspired by Islamic tilework, exploring the beauty of interlocking shapes. Islamic geometric art is one of humanity\'s great artistic traditions; early exposure builds cultural pride, geometry appreciation, and careful colouring control.'],
            ['title' => 'Wax Resist Painting',                   'emoji' => '🕯️', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 20, 'activity_type' => 'craft',       'skill' => 'Material science: hydrophobic surfaces', 'description' => 'Draw with a white wax crayon on white paper, then brush over with watercolour paint to reveal the hidden picture. Wax resist creates a "magic reveal" experience that also demonstrates the science of hydrophobic surfaces — why wax and water don\'t mix.'],

