            ['title' => 'Marbling with Oil and Water',           'emoji' => '🌀', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 20, 'activity_type' => 'craft',       'skill' => 'Abstract pattern and chance art',  'description' => 'Drop food colouring into an oil-water tray, swirl gently, then print on paper. Marbling produces uniquely beautiful, unrepeatable patterns and teaches children that not all art requires precise control — chance, randomness, and letting go are also artistic skills.'],
            ['title' => 'Simple Loom Weaving',                   'emoji' => '🧶', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 25, 'activity_type' => 'craft',       'skill' => 'Fine motor persistence and craftsmanship', 'description' => 'Weave yarn strips over and under the warp threads of a small wooden loom. Loom weaving demands fine motor precision, sequential memory, bilateral coordination, and sustained focus — it is one of the most cognitively demanding fine motor crafts available at preschool level.'],
            ['title' => 'Resist Stars with Masking Tape',        'emoji' => '⭐', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 20, 'activity_type' => 'craft',       'skill' => 'Masking technique and anticipation', 'description' => 'Press star-shaped tape stickers onto black paper, paint over in vibrant colour, let dry, then peel the tape to reveal white stars. Tape resist art introduces the concept of negative space and delayed gratification — the result cannot be seen until the tape is removed.'],
            ['title' => 'Drawing Animals from Simple Shapes',    'emoji' => '🐸', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'craft',       'skill' => 'Directed drawing and spatial decomposition', 'description' => 'Follow step-by-step directions to build an animal drawing from circles, ovals, and rectangles. Directed drawing teaches children to decompose complex forms into simple geometric parts — a spatial reasoning skill that transfers to architecture, engineering, and mathematical modelling.'],
            ['title' => 'Thumb Print Art',                       'emoji' => '👍', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'craft',       'skill' => 'Fingerprint uniqueness and identity', 'description' => 'Press thumb in ink and stamp repeatedly, then add detail marks to transform each thumbprint into a tiny creature. Thumbprint art introduces the idea that each person\'s fingerprint is uniquely theirs — connecting biology, identity, and mark-making in one playful activity.'],
            ['title' => 'Mixed Media Collage: Texture Layers',   'emoji' => '🗃️', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 25, 'activity_type' => 'craft',       'skill' => 'Mixed media composition',          'description' => 'Combine paint, torn paper, fabric scraps, and stickers on one artwork. Mixed media work teaches children that there are no fixed rules in art — that materials can be combined and layered freely, developing creative risk-taking and compositional decisions.'],
            ['title' => 'Silhouette Cityscape',                  'emoji' => '🌆', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 20, 'activity_type' => 'craft',       'skill' => 'Negative silhouette contrast',     'description' => 'Tear black paper into building shapes and paste onto a sunset-coloured background. Silhouette art introduces the concept that a shape (negative space) can tell a story as powerfully as a detailed drawing — a foundational principle of graphic design and visual communication.'],
            ['title' => 'Photographic Exploration Walk',         'emoji' => '📸', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 20, 'activity_type' => 'outdoor',     'skill' => 'Visual framing and composition',   'description' => 'Use a tablet or camera to photograph things that look beautiful or interesting on a nature walk. Photography teaches children to actively look for visual composition — framing, foreground, and the "decisive moment" — building visual literacy skills that apply across all media.'],
            ['title' => 'Body Painting Prints (Hands and Feet)', 'emoji' => '🖐️', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'craft',       'skill' => 'Body awareness through art',       'description' => 'Press paint-covered hands and feet onto large paper, then see the shape left behind. Body print art brings together self-awareness, proprioception, and mark-making in a joyfully messy way — the handprint is also perhaps the most universal symbol of human creative expression.'],
            ['title' => 'Drawing the Local Mosque or Building', 'emoji' => '🕌', 'age_tier' => 'preschool', 'subject' => 'art', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'craft',       'skill' => 'Architectural drawing and community', 'description' => 'Draw or paint the local mosque or a familiar building from observation or a photograph. Drawing buildings introduces architectural elements (arches, domes, minarets, windows) and connects art to community identity and belonging.'],

            // ═══════════════════════════════════════════════════════
            // MOTOR — batch 1 of 2 (activities 1–15)
            // ═══════════════════════════════════════════════════════
            ['title' => 'Hopscotch Number Game',                 'emoji' => '🎯', 'age_tier' => 'preschool', 'subject' => 'motor', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 15, 'activity_type' => 'game',        'skill' => 'Dynamic balance and number sense',  'description' => 'Hop through numbered chalk squares, calling out each number on landing. Hopscotch combines single-leg balance, bilateral coordination, sequential number learning, and directional awareness into the single most efficient physical-cognitive game in early childhood.'],
            ['title' => 'Catching a Large Ball',                 'emoji' => '🏐', 'age_tier' => 'preschool', 'subject' => 'motor', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 12, 'activity_type' => 'game',        'skill' => 'Hand-eye coordination: catching',   'description' => 'Stand 2 metres apart and throw and catch a large soft ball, moving further apart as success increases. Catching requires predicting ball trajectory, timing, and coordinating both arms simultaneously — a biomechanical challenge that develops rapidly between ages 3 and 5.'],
            ['title' => 'Balance Beam Walking',                  'emoji' => '🤸', 'age_tier' => 'preschool', 'subject' => 'motor', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 10, 'activity_type' => 'game',        'skill' => 'Dynamic balance and proprioception', 'description' => 'Walk heel-to-toe along a low balance beam (or a taped floor line), arms out for balance. Balance training activates the vestibular system, strengthens ankle and core stabilisation, and builds the postural control underlying all gross motor activities.'],
            ['title' => 'Skip and Gallop Across the Room',       'emoji' => '🏃', 'age_tier' => 'preschool', 'subject' => 'motor', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 10, 'activity_type' => 'outdoor',     'skill' => 'Gross motor locomotion patterns',   'description' => 'Practise skipping and galloping across an open space. Skipping (which requires alternating legs) is a complex bilateral coordination milestone that most children achieve between ages 4 and 6 — and that directly signals integration of the brain hemispheres.'],
            ['title' => 'Threading Beads on a Lace',             'emoji' => '📿', 'age_tier' => 'preschool', 'subject' => 'motor', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 12, 'activity_type' => 'hands_on',    'skill' => 'Fine motor: bilateral threading',   'description' => 'Thread large wooden beads onto a stiff lace, making a pattern. Threading beads requires the two hands to play different roles simultaneously — one guides the lace, one holds the bead — building the bimanual independence that underlies all tool use.'],
            ['title' => 'Pencil Grip Practice with Proper Hold', 'emoji' => '✏️', 'age_tier' => 'preschool', 'subject' => 'motor', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Dynamic tripod pencil grip',        'description' => 'Hold a pencil in the correct dynamic tripod grip (thumb, index, and middle finger) and draw simple shapes. Correct grip established before age 5, when habits are still forming, prevents the compensatory grips that cause handwriting fatigue and pain in later schooling.'],
            ['title' => 'Kicking a Ball Accurately',             'emoji' => '⚽', 'age_tier' => 'preschool', 'subject' => 'motor', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'outdoor',     'skill' => 'Eye-foot coordination and direction', 'description' => 'Kick a ball toward a target (cones or a goal) from increasing distances. Accurate kicking requires foot-eye coordination, weight transfer, and postural stability — a foundational gross motor skill with strong links to spatial reasoning.'],
            ['title' => 'Obstacle Course: Crawl, Jump, Balance', 'emoji' => '🏋️', 'age_tier' => 'preschool', 'subject' => 'motor', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'outdoor',     'skill' => 'Motor sequencing and body awareness', 'description' => 'Navigate a 5-station obstacle course involving crawling, jumping, balancing, and climbing. Obstacle courses demand motor sequencing — planned, smooth transitions between different movement patterns — building the motor planning capacity linked to executive function.'],
            ['title' => 'Tearing and Gluing Refined Practice',   'emoji' => '🗂️', 'age_tier' => 'preschool', 'subject' => 'motor', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'hands_on',    'skill' => 'Fine motor grip and tool control',  'description' => 'Tear newspaper precisely along ruled lines and glue each strip neatly onto card. The combination of controlled tearing (bilateral grip and pressure) with controlled gluing (pincer and spreading) represents a demanding fine motor sequence with immediate artistic reward.'],
            ['title' => 'Snipping with Scissors: Fringes',       'emoji' => '✂️', 'age_tier' => 'preschool', 'subject' => 'motor', 'age_min' => 3, 'age_max' => 4, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Scissor snipping: entry level',     'description' => 'Make small snipping cuts along the edge of a paper strip to create a fringe. Single-cut snipping is the developmentally appropriate first scissor skill; attempting to cut along continuous curved lines before snipping is mastered leads to frustration and compensatory habits.'],
            ['title' => 'Rolling, Patting, and Cutting Playdough', 'emoji' => '🫘', 'age_tier' => 'preschool', 'subject' => 'motor', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'hands_on',    'skill' => 'Fine motor strength and control',   'description' => 'Roll playdough into snakes and balls, pat flat, then cut with a plastic knife. The resistance of playdough makes each motion a strength-building exercise; intrinsic hand muscles strengthened through play develop the grip and endurance required for extended writing.'],
            ['title' => 'Throwing at a Target: Underarm',        'emoji' => '🎳', 'age_tier' => 'preschool', 'subject' => 'motor', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'outdoor',     'skill' => 'Ballistic projection: throwing accuracy', 'description' => 'Throw a beanbag underarm to knock down a target. Accurate throwing requires weight transfer, arm swing trajectory prediction, and release timing — a demanding set of ballistic motor skills that mature progressively between ages 3 and 8.'],
            ['title' => 'Pumping a Swing Independently',         'emoji' => '🪤', 'age_tier' => 'preschool', 'subject' => 'motor', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'outdoor',     'skill' => 'Rhythmic motor planning (pumping)',  'description' => 'Learn to push the swing independently by timing the leg swing with the pendulum arc. Independent pumping requires sophisticated bilateral rhythm coordination and represents a significant motor planning milestone typically achieved between ages 4 and 6.'],
            ['title' => 'Fine Motor Peg Transfer',               'emoji' => '🪡', 'age_tier' => 'preschool', 'subject' => 'motor', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Pincer and lateral pinch strength',  'description' => 'Transfer small objects from one tray to another using pegs (clothes pegs or tweezers). Pincer-strength activities that use lateral resistance (opening a peg against spring tension) build the exact hand muscles required for sustained pen and pencil use.'],
            ['title' => 'Sticker Placement on Target Dots',      'emoji' => '🔵', 'age_tier' => 'preschool', 'subject' => 'motor', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Visual-motor precision placement',   'description' => 'Peel stickers and place each exactly on a small printed dot. Sticker placement is a deceptively demanding visual-motor task — peeling requires a fingernail-edge pinch, and precise placement requires visual-spatial targeting — both critical fine motor prerequisites.'],

            // ═══════════════════════════════════════════════════════
            // MOTOR — batch 2 of 2 (activities 16–25)
            // ═══════════════════════════════════════════════════════
            ['title' => 'Hammering Tees into Foam Board',         'emoji' => '🔨', 'age_tier' => 'preschool', 'subject' => 'motor', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'hands_on',    'skill' => 'Tool use and hand-eye coordination',  'description' => 'Hammer golf tees into a thick foam block. Hammering requires precise aim, controlled force calibration, and lateral stability — and is one of the most direct analogues to real-world tool use available to a preschooler, building deep respect for precision and cause-effect.'],
            ['title' => 'Running and Changing Direction on Cue',  'emoji' => '🏃', 'age_tier' => 'preschool', 'subject' => 'motor', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'outdoor',     'skill' => 'Agility, stop-start motor control',   'description' => 'Run freely, then freeze and change direction the instant you hear a clap. Agility drills develop reactive motor control and the proprioceptive awareness needed to redirect momentum safely — directly reducing sports-related injury risk throughout life.'],
            ['title' => 'Lacing and Tying Shoelaces',             'emoji' => '👟', 'age_tier' => 'preschool', 'subject' => 'motor', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'hands_on',    'skill' => 'Bimanual fine motor sequencing',      'description' => 'Practise lacing a large foam shoe board, then learn the loop-and-pull tie method. Shoelace tying is the single most bimanually complex fine motor task of early childhood — requiring coordinated two-hand manipulation, sequential memory, and spatial reasoning simultaneously.'],
            ['title' => 'Pouring Water Between Jugs',             'emoji' => '🫙', 'age_tier' => 'preschool', 'subject' => 'motor', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Wrist control and visual monitoring',  'description' => 'Pour water from a small jug into a series of narrow-mouthed cups without spilling. Precision pouring builds wrist supination/pronation control and the visual-motor feedback loop — and is a Montessori "practical life" activity with direct links to mealtime independence.'],
            ['title' => 'Yoga Animal Poses for Balance',          'emoji' => '🧘', 'age_tier' => 'preschool', 'subject' => 'motor', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'hands_on',    'skill' => 'Static balance and body schema',       'description' => 'Hold animal yoga poses — cat, dog, tree, cobra — for 5 seconds each. Yoga improves static balance, body schema mapping, trunk stability, and focused breathing; children who regularly practise yoga show significantly better self-regulation in kindergarten.'],
            ['title' => 'Dressing and Buttoning Independently',   'emoji' => '🧥', 'age_tier' => 'preschool', 'subject' => 'motor', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Dressing: buttoning and zipping',      'description' => 'Practise doing up 3 large buttons and a zip on a dressing frame. Fastener skills directly build independence and self-esteem; the complex pinch-and-place-in-hole sequence of buttoning is one of the finest available fine motor challenges at this age.'],
            ['title' => 'Jumping on the Spot: 10 in a Row',       'emoji' => '🐸', 'age_tier' => 'preschool', 'subject' => 'motor', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'outdoor',     'skill' => 'Two-foot take-off and landing',        'description' => 'Jump as many times as possible on the spot with both feet, landing softly. Bilateral jumping trains lower limb strength, impact absorption (important for joint health), and rhythmic motor timing — and boosts classroom attention when used as a movement break.'],
            ['title' => 'Copying a Clapping Rhythm Pattern',      'emoji' => '👏', 'age_tier' => 'preschool', 'subject' => 'motor', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'game',        'skill' => 'Auditory-motor sequencing',            'description' => 'Listen to a clapped rhythm pattern (e.g., 3+2+1) and reproduce it exactly. Rhythm reproduction links auditory working memory to motor sequencing — a skill that underpins phonological awareness, musical ability, and multi-step task completion.'],
            ['title' => 'Simon Says Full-Body Actions',           'emoji' => '🕹️', 'age_tier' => 'preschool', 'subject' => 'motor', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'game',        'skill' => 'Motor inhibition and listening',       'description' => 'Play Simon Says with full-body commands: touch your knees, spin, hop, freeze. The inhibitory challenge of not acting on commands that lack "Simon says" develops the motor inhibition and listening accuracy that form the behavioural regulation core of school readiness.'],
            ['title' => 'Clay Sculpting with Rolling Tools',      'emoji' => '🏺', 'age_tier' => 'preschool', 'subject' => 'motor', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'hands_on',    'skill' => 'Fine motor force and form creation',   'description' => 'Roll, pinch, and shape air-dry clay using a rolling pin and clay tools. Clay sculpting demands a far broader range of hand movements than playdough — pressing, pinching, scoring, and carving — providing a complete intrinsic hand muscle workout.'],

            // ═══════════════════════════════════════════════════════
            // SOCIAL — batch 1 of 2 (activities 1–15)
            // ═══════════════════════════════════════════════════════
            ['title' => 'Cooperative Block Tower Building',       'emoji' => '🏗️', 'age_tier' => 'preschool', 'subject' => 'social', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 12, 'activity_type' => 'game',        'skill' => 'Turn-taking and joint goal pursuit',   'description' => 'Take turns adding one block each to build the tallest possible tower together, without it falling. Cooperative building requires joint attention, turn-taking, risk negotiation ("should we add one more?"), and shared ownership of outcome — intensive social learning in a physical format.'],
            ['title' => 'Feelings Faces Mirror Game',             'emoji' => '😄', 'age_tier' => 'preschool', 'subject' => 'social', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 10, 'activity_type' => 'game',        'skill' => 'Emotional recognition and mirroring',  'description' => 'Look in a mirror together and take turns pulling different emotion faces for the other to name and copy. Deliberate emotion mirroring builds facial expression awareness, empathy (feeling what someone shows), and the emotion vocabulary that is the foundation of social communication.'],
            ['title' => 'Sharing a Limited Resource (One Box)',   'emoji' => '📦', 'age_tier' => 'preschool', 'subject' => 'social', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Sharing and fairness negotiation',     'description' => 'Give two children one box of crayons or building pieces to share for a joint project. Sharing a limited resource creates authentic, naturally occurring conflict and resolution opportunities — far more effective than talking about sharing in the abstract.'],
            ['title' => 'Playing a Simple Group Card Game',       'emoji' => '🃏', 'age_tier' => 'preschool', 'subject' => 'social', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'game',        'skill' => 'Rule-following and good sportsmanship', 'description' => 'Play a simple card game like Snap or Go Fish with 2–4 players. Structured games establish the critical social norm that fun requires rule-following — and losing gracefully is one of the most practically useful social-emotional skills a child can acquire before starting school.'],
            ['title' => 'Greeting Visitors with Salaam',          'emoji' => '🤝', 'age_tier' => 'preschool', 'subject' => 'social', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 5,  'activity_type' => 'real_world',  'skill' => 'Islamic greeting etiquette',           'description' => 'Greet visitors at the door with "As-salamu alaykum" and a smile, then show them in. Learning the Islamic greeting instills both the spiritual reward of spreading peace and the practical social skill of polite, confident greeting — a lifelong social asset.'],

            // ═══════════════════════════════════════════════════════
            // SOCIAL — batch 2 of 2 (activities 16–20)
            // ═══════════════════════════════════════════════════════
            ['title' => 'Waiting for Your Turn Patiently',        'emoji' => '⏳', 'age_tier' => 'preschool', 'subject' => 'social', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'game',        'skill' => 'Patience, delayed gratification',     'description' => 'Practise waiting in short, structured turn-taking activities where waiting has a clear time limit. Patience is trained, not innate — structured waiting exercises grow the prefrontal cortex capacity for self-regulation that determines academic and life outcomes.'],
            ['title' => 'Role-Playing Being a Helper',             'emoji' => '🤲', 'age_tier' => 'preschool', 'subject' => 'social', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'real_world',  'skill' => 'Prosocial orientation: helping',      'description' => 'Role-play being a helper — setting the table, tidying toys, carrying a bag. Children who see themselves as "helpers" rather than being "told to help" develop a prosocial identity that persists into adulthood as intrinsic generosity rather than compliance.'],
            ['title' => 'Collaborative Painting One Big Canvas',   'emoji' => '🖌️', 'age_tier' => 'preschool', 'subject' => 'social', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 20, 'activity_type' => 'craft',       'skill' => 'Co-regulation and shared creative space', 'description' => 'Two or more children paint together on one large shared sheet with a negotiated theme. Shared artwork requires constant co-regulation — adjusting personal plans in response to what a partner creates — a sophisticated social-emotional skill mirroring adult collaborative work.'],
            ['title' => 'Saying Sorry and Making It Right',        'emoji' => '💛', 'age_tier' => 'preschool', 'subject' => 'social', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'real_world',  'skill' => 'Repair: apology and restitution',     'description' => 'After a conflict, practise a genuine apology: "I\'m sorry I ___. Next time I will ___." then do something kind. Teaching repair behaviour (not just apology words) builds the capacity for authentic reconciliation — the relational skill underlying all long-term friendships and family bonds.'],
            ['title' => 'Community Roles Roleplay',                'emoji' => '🏥', 'age_tier' => 'preschool', 'subject' => 'social', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'game',        'skill' => 'Understanding community interdependence', 'description' => 'Roleplay different community helpers — doctor, teacher, baker, street sweeper — discussing what each one contributes. Understanding that every role serves the community cultivates gratitude, respect for all occupations, and a sense of one\'s own future role in society.'],

            // ═══════════════════════════════════════════════════════
            // CHARACTER — batch 1 of 1 (activities 1–20)
            // ═══════════════════════════════════════════════════════
            ['title' => 'Honesty Role-Play: Telling the Truth',   'emoji' => '🌟', 'age_tier' => 'preschool', 'subject' => 'character', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 12, 'activity_type' => 'game',        'skill' => 'Honesty and moral reasoning',          'description' => 'Role-play scenarios where telling the truth is hard (broken cup, accidental mess) and discuss what a truthful person does. Character education is most effective when it involves lived narrative scenarios rather than abstract instruction — children need to rehearse virtuous choice in simulated pressure.'],
            ['title' => 'Gratitude Jar: One Good Thing Daily',    'emoji' => '🫙', 'age_tier' => 'preschool', 'subject' => 'character', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 5,  'activity_type' => 'real_world',  'skill' => 'Gratitude, positive attention bias',   'description' => 'Each evening, draw or dictate one thing you are grateful for and add it to the family gratitude jar. Daily gratitude practice shifts attentional bias toward positive noticing — a habit with robust evidence for increased happiness, resilience, and social warmth.'],
            ['title' => 'Patience Practice: Waiting 3 Minutes',   'emoji' => '⏱️', 'age_tier' => 'preschool', 'subject' => 'character', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 8,  'activity_type' => 'real_world',  'skill' => 'Patience, delayed gratification',      'description' => 'Set a 3-minute timer before getting a snack or treat, and practise waiting calmly. Deliberate patience training (not punishment but practice) gradually extends the time a child can defer gratification — the single most powerful predictor of long-term success identified in developmental psychology.'],
            ['title' => 'Courage: Doing Something a Bit Scary',   'emoji' => '🦁', 'age_tier' => 'preschool', 'subject' => 'character', 'age_min' => 4, 'age_max' => 5, 'is_free' => true,  'duration' => 10, 'activity_type' => 'real_world',  'skill' => 'Courage and self-push',                'description' => 'Identify something slightly scary (a higher slide, talking to a new child) and try it with a trusted adult nearby. Exposing children to manageable challenge while supported builds courage as a habitual disposition — not recklessness, but the trained willingness to act despite fear.'],
            ['title' => 'Kindness Challenge: One Act Each Day',   'emoji' => '💝', 'age_tier' => 'preschool', 'subject' => 'character', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 5,  'activity_type' => 'real_world',  'skill' => 'Kindness habit formation',             'description' => 'Each morning, choose one specific act of kindness to do that day and report back in the evening. Named, intentional kindness — rather than spontaneous kindness — builds kind identity: a child who describes themselves as a kind person then behaves consistently with that self-concept.'],
            ['title' => 'Responsibility: Caring for a Plant',     'emoji' => '🌱', 'age_tier' => 'preschool', 'subject' => 'character', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'real_world',  'skill' => 'Responsibility: stewardship',           'description' => 'Own and tend a small potted plant — water it, check the soil, and give it light. Responsibility becomes internalised when a child sees direct evidence that their actions sustain another living thing — the plant grows OR it wilts based purely on their stewardship.'],
            ['title' => 'Respecting Personal Belongings',         'emoji' => '🏡', 'age_tier' => 'preschool', 'subject' => 'character', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'real_world',  'skill' => 'Respect for property boundaries',      'description' => 'Practise asking "Can I use this?" before borrowing and returning things carefully. Learning the social contract of permission and return before school age prevents the possessiveness and peer conflict that arise when children have never been taught ownership respect.'],
            ['title' => 'Perseverance: Finishing Hard Puzzles',   'emoji' => '🧩', 'age_tier' => 'preschool', 'subject' => 'character', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'hands_on',    'skill' => 'Grit, frustration tolerance',          'description' => 'Attempt a puzzle with 2–3 pieces more than the child can easily solve, without help until stuck. Calibrated challenge — where success requires genuine effort but is achievable — is the precise condition needed to build grit, a character trait more predictive of success than IQ.'],
            ['title' => 'Generosity: Making a Gift for Someone',  'emoji' => '🎁', 'age_tier' => 'preschool', 'subject' => 'character', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 20, 'activity_type' => 'craft',       'skill' => 'Generosity and giving',                'description' => 'Create a handmade gift — a drawing, a card, a clay pot — for a grandparent, friend, or neighbour. The act of spending effort to make something for someone else (not receiving) is the primary mechanism by which generosity becomes a stable character trait rather than a commanded behaviour.'],
            ['title' => 'Tidiness: Putting Everything in Its Place', 'emoji' => '🧹', 'age_tier' => 'preschool', 'subject' => 'character', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'real_world',  'skill' => 'Order and environmental responsibility', 'description' => 'Tidy up by placing every item in its correct place — not "put away" randomly but into a labelled home. Tidiness habits established at preschool age require labelled homes for all objects; children who grow up in environments with clear places for things develop organisational competence naturally.'],
            ['title' => 'Controlling Anger: The Breathing Flower', 'emoji' => '🌸', 'age_tier' => 'preschool', 'subject' => 'character', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'hands_on',    'skill' => 'Anger regulation, breathwork',         'description' => 'When angry, "smell the flower" (slow nose inhale) and "blow the candle" (slow mouth exhale) three times. Teaching physiological self-regulation tools before the age of emotion regulation maturity (age 7) gives children a reliable toolkit they will use independently — the foundation of emotional resilience.'],
            ['title' => 'Following Instructions Exactly',          'emoji' => '👂', 'age_tier' => 'preschool', 'subject' => 'character', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'game',        'skill' => 'Obedience, listening compliance',      'description' => 'Give a 3-step instruction (e.g., "Pick up the red pencil, put it in the box, bring me the box") and see if it is followed exactly. Practising exact instruction-following builds the listening compliance required for safe group settings — and contrasts valued obedience with mechanical, virtue-free rule-following.'],
            ['title' => 'Admitting Mistakes Confidently',          'emoji' => '✅', 'age_tier' => 'preschool', 'subject' => 'character', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'real_world',  'skill' => 'Accountability without shame',         'description' => 'Model and roleplay saying "I made a mistake. Here is what I will do next time." without shame or self-blame. Healthy accountability — owning errors without catastrophising — is one of the most protective psychological skills for long-term mental health and relationships.'],
            ['title' => 'Contentment: Appreciating What You Have', 'emoji' => '😌', 'age_tier' => 'preschool', 'subject' => 'character', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'real_world',  'skill' => 'Gratitude, non-materialism',           'description' => 'Name three things you love about your home, family, and self before screen time. Qana\'ah (Islamic contentment) is not passive acceptance but active noticing of blessing — a counter-practice to constant comparison and desire stimulation that is the default of modern childhood.'],
            ['title' => 'Empathy Practice: How Does She Feel?',   'emoji' => '💬', 'age_tier' => 'preschool', 'subject' => 'character', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'game',        'skill' => 'Theory of mind, empathy',              'description' => 'Look at a picture of a child in different situations and ask "How do you think she feels? Why?" Perspective-taking exercises accelerate the development of theory of mind (understanding others have different feelings and thoughts) — the neurocognitive foundation of empathy, compassion, and social intelligence.'],

            // ═══════════════════════════════════════════════════════
            // CREATIVE — batch 1 of 1 (activities 1–20)
            // ═══════════════════════════════════════════════════════
            ['title' => 'Imaginative Play: Pillow Fort Kingdom',  'emoji' => '🏰', 'age_tier' => 'preschool', 'subject' => 'creative', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 30, 'activity_type' => 'game',        'skill' => 'Imaginative world-building',           'description' => 'Build a fort from cushions and blankets and spend time inside it in an imaginary world you invent. Open-ended pretend play inside a self-constructed space stimulates theory of mind, narrative creation, emotional regulation, and symbolic thinking more efficiently than any structured educational activity.'],
            ['title' => 'Making Up a Story: Oral Storytelling',   'emoji' => '📖', 'age_tier' => 'preschool', 'subject' => 'creative', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 12, 'activity_type' => 'game',        'skill' => 'Narrative invention and sequencing',   'description' => 'Without a book, invent a story out loud — beginning, middle, and end — using a random card prompt (e.g., a whale, a storm, a lamp). Oral storytelling without a source text trains pure narrative thinking: organising events causally, sustaining a character, and resolving conflict — the roots of written composition.'],
            ['title' => 'Puppet Show Performance',                'emoji' => '🎭', 'age_tier' => 'preschool', 'subject' => 'creative', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 20, 'activity_type' => 'game',        'skill' => 'Drama and voice characterisation',    'description' => 'Create sock or paper-bag puppets and perform a short play for the family. Puppet performance provides the psychological distance of a "safe character" — allowing shy children to express, emote, and voice-act freely — a powerful tool for language confidence and emotional expression.'],
            ['title' => 'Drawing an Imaginary Animal',            'emoji' => '🦄', 'age_tier' => 'preschool', 'subject' => 'creative', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 12, 'activity_type' => 'craft',       'skill' => 'Creative recombination of concepts',  'description' => 'Draw any animal you can imagine — it does not need to exist. Merge two animals, add wings, give it new colours. Imaginary creature design is pure combinatorial creativity — taking known elements and recombining them in novel configurations — the same cognitive mode as adult innovation.'],
            ['title' => 'Sound Effects Soundscape Creation',      'emoji' => '🎵', 'age_tier' => 'preschool', 'subject' => 'creative', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 12, 'activity_type' => 'hands_on',    'skill' => 'Sound awareness and creative production', 'description' => 'Create a jungle, city, or beach soundscape using only your voice and household objects. Sound design trains children to deconstruct environments into constituent sounds, then synthetically recreate them — training auditory attention, categorisation, and creative sound thinking.'],
            ['title' => 'Inventing a New Game with Rules',         'emoji' => '🎮', 'age_tier' => 'preschool', 'subject' => 'creative', 'age_min' => 4, 'age_max' => 5, 'is_free' => true,  'duration' => 15, 'activity_type' => 'game',        'skill' => 'Game design: rules and play balance',  'description' => 'Invent a completely new game using any objects at hand, decide the rules, and teach it to someone. Designing a game trains logical thinking (rules must be consistent), social thinking (rules must be fair), and creative thinking (novel mechanics) simultaneously.'],
            ['title' => 'Imaginative Small World Play: Miniatures', 'emoji' => '🏘️', 'age_tier' => 'preschool', 'subject' => 'creative', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 30, 'activity_type' => 'game',        'skill' => 'Symbolic miniature play and narrative', 'description' => 'Set up a miniature world (farm, village, ocean floor) with small figures and build stories within it. Small world play activates the deepest level of symbolic thinking — the child stands in for an entire universe, assigns agency to miniature actors, and controls narrative causality.'],
            ['title' => 'Designing Your Dream Home',               'emoji' => '🏠', 'age_tier' => 'preschool', 'subject' => 'creative', 'age_min' => 4, 'age_max' => 5, 'is_free' => true,  'duration' => 15, 'activity_type' => 'craft',       'skill' => 'Spatial design and dream-projection',  'description' => 'Draw or build with blocks your ideal home — every room, garden, and detail that matters to you. Dream-home design reveals children\'s deepest values and desires while training spatial organisation, functional design thinking, and the connection between imagination and reality.'],
            ['title' => 'Action Rhyme Composition',                'emoji' => '🎶', 'age_tier' => 'preschool', 'subject' => 'creative', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 10, 'activity_type' => 'game',        'skill' => 'Rhythm, rhyme and movement creation',  'description' => 'Make up your own short action rhyme — 4 lines with rhyming ends — and add movements for each line. Rhyme composition at preschool age develops phonological awareness (hearing similar sound endings), memory for language patterns, and metrical sensitivity foundational for reading fluency.'],
            ['title' => 'Pretend Restaurant or Shop',              'emoji' => '🍽️', 'age_tier' => 'preschool', 'subject' => 'creative', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 20, 'activity_type' => 'game',        'skill' => 'Role-play, money concepts, literacy',  'description' => 'Set up a pretend restaurant or shop with a handwritten menu or price tags. Pretend shop play integrates symbolic play (money), emergent litercy (making menus), early maths (calculating change), and social protocols (serving, ordering) into a single joyful context.'],
            ['title' => 'Three-Idea Brainstorm Challenge',          'emoji' => '💡', 'age_tier' => 'preschool', 'subject' => 'creative', 'age_min' => 4, 'age_max' => 5, 'is_free' => true,  'duration' => 8,  'activity_type' => 'game',        'skill' => 'Ideational fluency and divergent thinking', 'description' => 'Name 3 different things you could do with a cardboard tube. Then try 3 more. Divergent thinking — generating multiple uses for one object — is the core measurement of creative intelligence and can be trained explicitly through repeated practice.'],
            ['title' => 'Nature Garden Creation in a Tray',         'emoji' => '🌿', 'age_tier' => 'preschool', 'subject' => 'creative', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 25, 'activity_type' => 'outdoor',     'skill' => 'Natural materials design thinking',   'description' => 'Collect outdoor materials — stones, sticks, leaves, sand — and arrange them into a miniature garden in a tray. Natural loose-parts design develops open-ended constructive play: there is no wrong answer, every configuration is valid, every child produces a unique aesthetic response.'],
            ['title' => 'Inventing a Word: Portmanteau Play',      'emoji' => '🔡', 'age_tier' => 'preschool', 'subject' => 'creative', 'age_min' => 4, 'age_max' => 5, 'is_free' => true,  'duration' => 8,  'activity_type' => 'game',        'skill' => 'Linguistic creativity and word-play',  'description' => 'Mash two words together to make a funny new word (e.g., "snorange" = snow + orange). Draw what the new thing looks like. Word-blending play trains phoneme manipulation, semantic awareness, and the understanding that language is malleable — a metalinguistic insight far above age expectation.'],
            ['title' => 'Music Making: Household Percussion Band', 'emoji' => '🥁', 'age_tier' => 'preschool', 'subject' => 'creative', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 15, 'activity_type' => 'hands_on',    'skill' => 'Rhythm, timbre and music play',        'description' => 'Use pots, boxes, and spoons to create percussion instruments and play together. Percussion ensemble play (without electronics or recorded music) develops rhythm internalisation, listening awareness, and interpersonal synchronisation — the neural basis of musical ability and social timing.'],
            ['title' => 'Clay Sculpture: Build an Imaginary Creature', 'emoji' => '🦎', 'age_tier' => 'preschool', 'subject' => 'creative', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 20, 'activity_type' => 'craft',       'skill' => '3D creative sculpting and fantasy',   'description' => 'Sculpt a never-seen-before creature from clay, giving it a name, habitat, and diet. Three-dimensional creative sculpting extends imaginative world-building into spatial form — reinforcing the connection between imagination and physical creation that is the basis of all design, architecture, and engineering.'],
            ['title' => 'Shadow Puppet Theatre (Hand Shadows)',    'emoji' => '🌑', 'age_tier' => 'preschool', 'subject' => 'creative', 'age_min' => 4, 'age_max' => 5, 'is_free' => true,  'duration' => 15, 'activity_type' => 'game',        'skill' => 'Light, shadow and gestural drama',    'description' => 'In a darkened room with a torch, create hand shadow shapes on the wall and invent a short story. Shadow play teaches basic optics (light, shadow, distance) while developing gestural precision, physical control, and the narrative skills of theatre performance.'],
            ['title' => 'Building a Cardboard Box Town',           'emoji' => '🏙️', 'age_tier' => 'preschool', 'subject' => 'creative', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 40, 'activity_type' => 'craft',       'skill' => 'Community design and spatial thinking', 'description' => 'Cut and decorate cereal boxes to make buildings, then arrange them into a town with roads, parks, and a mosque. Large-scale constructive play with functional community layout requires city planning thinking — who lives where, what goes near what, and why — a spatial-social thinking challenge.'],
            ['title' => 'Emotion Drawing: Paint How You Feel',     'emoji' => '🎨', 'age_tier' => 'preschool', 'subject' => 'creative', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'craft',       'skill' => 'Expressive art and emotional labelling', 'description' => 'Choose colours and shapes that represent how you feel right now and paint them freely. Abstract expressive painting gives preschoolers a visual language for inner states before verbal emotional vocabulary is sophisticated enough — it externalises emotion and makes it visible and discussable.'],
            ['title' => 'Nature Loose Parts Architecture',          'emoji' => '🌲', 'age_tier' => 'preschool', 'subject' => 'creative', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 20, 'activity_type' => 'outdoor',     'skill' => 'Natural design and construction',     'description' => 'Use only natural materials collected outdoors — sticks, leaves, mud, stones — to build a small structure. Loose parts construction with natural materials engages children in genuine architectural problem-solving with materials that have real structural constraints (sticks bend; stones roll), unlike plastic blocks which have artificial snap relationships.'],
            ['title' => 'Writing and Illustrating a Mini-Book',    'emoji' => '📚', 'age_tier' => 'preschool', 'subject' => 'creative', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 20, 'activity_type' => 'craft',       'skill' => 'Narrative + illustration + authorship',  'description' => 'Fold 3 sheets of paper to create an 8-page booklet, then draw and dictate the text for each page. Making a book with a beginning, middle, and end consolidates narrative structure understanding, builds print concept awareness, and gives the profound psychological experience of being an author.'],

            // ═══════════════════════════════════════════════════════
            // COGNITIVE — batch 1 of 2 (activities 1–5)
            // ═══════════════════════════════════════════════════════
            ['title' => 'Sorting Objects by Two Attributes',       'emoji' => '🔴', 'age_tier' => 'preschool', 'subject' => 'cognitive', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 12, 'activity_type' => 'hands_on',    'skill' => 'Multi-attribute classification',      'description' => 'Sort a mixed collection by two rules at once (e.g., big red things, small blue things). Sorting by two attributes simultaneously requires holding two rules in working memory while evaluating each object — a foundational logical thinking skill that directly predicts mathematical ability.'],
            ['title' => 'What Does Not Belong? Odd-One-Out',       'emoji' => '🔍', 'age_tier' => 'preschool', 'subject' => 'cognitive', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 10, 'activity_type' => 'game',        'skill' => 'Category reasoning and exception detection', 'description' => 'Look at a set of 4 pictures and identify which one doesn\'t belong, then explain why. Odd-one-out tasks require identifying the defining category rule and recognising which item violates it — a discriminative reasoning skill central to logical thinking and concept formation.'],
            ['title' => 'Gravity Ramp Experiment: Fast vs Slow',   'emoji' => '⚡', 'age_tier' => 'preschool', 'subject' => 'cognitive', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 15, 'activity_type' => 'hands_on',    'skill' => 'Hypothesis-testing: cause and effect',  'description' => 'Build a ramp from a plank and test which objects roll faster — smooth ball vs rough ball, heavy vs light. Ramp experiments introduce the concept of controlled variables and hypothesis testing in a purely physical, hands-on context — the earliest form of genuine scientific method.'],
            ['title' => 'Memory Card Pairs: 6-Pair Game',           'emoji' => '🃏', 'age_tier' => 'preschool', 'subject' => 'cognitive', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'game',        'skill' => 'Visual working memory and recall',    'description' => 'Flip all cards face-down and find matching pairs by memory. Memory card games are among the purest available working memory trainers — requiring rapid encoding of spatial location, brief retention, and precise recall — all capacities directly linked to academic achievement.'],
            ['title' => 'Following a 3-Step Map to Find Treasure', 'emoji' => '🗺️', 'age_tier' => 'preschool', 'subject' => 'cognitive', 'age_min' => 4, 'age_max' => 5, 'is_free' => true,  'duration' => 15, 'activity_type' => 'game',        'skill' => 'Spatial map reading and direction following', 'description' => 'Read a simple hand-drawn map with 3 steps to find a hidden item. Map-reading requires mentally translating a flat symbolic representation into three-dimensional physical navigation — an advanced spatial cognition skill that is precursor to geometry, geography, and directional reasoning.'],

            // ═══════════════════════════════════════════════════════
            // COGNITIVE — batch 2 of 2 (activities 6–20)
            // ═══════════════════════════════════════════════════════
            ['title' => 'Sequencing Story Pictures',              'emoji' => '🖼️', 'age_tier' => 'preschool', 'subject' => 'cognitive', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'hands_on',    'skill' => 'Temporal sequencing and causal logic', 'description' => 'Arrange 4 jumbled story pictures into the correct narrative order. Sequencing tasks require reconstructing temporal and causal relationships — what caused what, what came before what — a foundational logic skill that directly underlies narrative comprehension and mathematical reasoning.'],
            ['title' => 'Complete the Pattern: Beads',            'emoji' => '🔵', 'age_tier' => 'preschool', 'subject' => 'cognitive', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Abstract pattern extension',           'description' => 'Look at a repeating bead pattern (ABBC ABBC...) and continue it. Pattern extension requires abstracting the underlying rule, not just copying — a capacity that is the foundational precursor to algebraic thinking and mathematical generalisation.'],
            ['title' => 'Problem Solving: Stuck Toy Retrieval',   'emoji' => '🔧', 'age_tier' => 'preschool', 'subject' => 'cognitive', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 10, 'activity_type' => 'game',        'skill' => 'Physical problem-solving and tool use', 'description' => 'Place a small toy out of reach and ask how to get it using only available objects. Physical reasoning tasks — "how can I reach that without climbing on furniture?" — develop means-end thinking, causal chains, and creative problem-solving in concrete physical space.'],
            ['title' => 'Floating and Sinking Prediction Game',   'emoji' => '🚢', 'age_tier' => 'preschool', 'subject' => 'cognitive', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 15, 'activity_type' => 'hands_on',    'skill' => 'Scientific prediction and observation', 'description' => 'Predict whether each object will float or sink, test it, and record the result. The predict-test-review cycle, even at preschool level, establishes the empirical habit of forming a hypothesis before testing rather than rationalising observations after the fact.'],
            ['title' => 'Shape Tangram Puzzles',                  'emoji' => '🔷', 'age_tier' => 'preschool', 'subject' => 'cognitive', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'hands_on',    'skill' => 'Spatial reasoning: rotation and fitting', 'description' => 'Arrange tangram pieces to recreate silhouette shapes. Tangrams require mental rotation — imagining how a shape will look when turned — a spatial reasoning skill with the strongest available evidence for predicting STEM aptitude and performance.'],
            ['title' => 'Asking Questions: Why? Inquiry Habit',   'emoji' => '❓', 'age_tier' => 'preschool', 'subject' => 'cognitive', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 10, 'activity_type' => 'real_world',  'skill' => 'Inquiry disposition and curiosity habit', 'description' => 'Choose one thing you see each day and ask "Why does that happen?" — then actually investigate. Cultivating the WHY habit — systematic inquiry rather than passive acceptance — is the single most impactful cognitive disposition a child can develop before school age.'],
            ['title' => 'Reverse Thinking: What if It Were Opposite?', 'emoji' => '🔄', 'age_tier' => 'preschool', 'subject' => 'cognitive', 'age_min' => 4, 'age_max' => 5, 'is_free' => true,  'duration' => 10, 'activity_type' => 'game',        'skill' => 'Counterfactual and reversal reasoning', 'description' => 'Ask "What if the sun came out at night?" or "What if dogs could talk?" and explore the consequences. Counterfactual thinking — imagining reversed or absent conditions — is a higher-order cognitive skill directly linked to scientific causal reasoning and creative problem-solving.'],
            ['title' => 'Jigsaw Puzzle: 20–30 Pieces Independently', 'emoji' => '🧩', 'age_tier' => 'preschool', 'subject' => 'cognitive', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 20, 'activity_type' => 'hands_on',    'skill' => 'Perseverance and visual-spatial matching', 'description' => 'Complete a 20–30 piece jigsaw independently. Independent jigsaw completion trains spatial part-whole reasoning, visual discrimination, trial-and-error persistence, and the self-regulatory ability to remain on-task through difficulty — all pillars of school readiness.'],
            ['title' => 'Categories Brainstorm: Name 5 Things',   'emoji' => '📋', 'age_tier' => 'preschool', 'subject' => 'cognitive', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 8,  'activity_type' => 'game',        'skill' => 'Category membership and verbal fluency', 'description' => 'Name 5 things that are: animals, things that fly, things you eat for breakfast. Category retrieval drills simultaneously train concept categorisation (what rule defines membership) and verbal fluency (fast efficient lexical access) — both key academic readiness skills.'],
            ['title' => 'Making Predictions Before Opening a Book', 'emoji' => '📖', 'age_tier' => 'preschool', 'subject' => 'cognitive', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Inferential prediction from visual cues', 'description' => 'Before reading, look only at the cover and make three predictions about the story. Pre-reading predictions activate prior knowledge, create a question-answering reading goal, and build inferential comprehension — the skill gap most predictive of reading comprehension difficulties in school.'],
            ['title' => 'Counting On: Starting from a Number',    'emoji' => '🔢', 'age_tier' => 'preschool', 'subject' => 'cognitive', 'age_min' => 4, 'age_max' => 5, 'is_free' => true,  'duration' => 10, 'activity_type' => 'game',        'skill' => 'Counting-on: early addition strategy', 'description' => 'Start from a given number (not 1) and count on: "5... 6, 7, 8." Counting-on (rather than counting-all) is the key transition marking the shift from immature to efficient mathematical reasoning and identifying a child who understands number as quantity not just sequence.'],
            ['title' => 'True or False: Real vs Pretend',          'emoji' => '🤔', 'age_tier' => 'preschool', 'subject' => 'cognitive', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 8,  'activity_type' => 'game',        'skill' => 'Reality vs fantasy discrimination',   'description' => 'State sentences ("Dogs can talk", "Ice melts in the sun") and decide if they are real or pretend. Real-versus-pretend discrimination is a critical developmental milestone: children who confuse fantasy and reality at school age face significant learning challenges in history, science, and social understanding.'],
            ['title' => 'Measuring with Non-Standard Units',       'emoji' => '📏', 'age_tier' => 'preschool', 'subject' => 'cognitive', 'age_min' => 4, 'age_max' => 5, 'is_free' => true,  'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Measurement concept: unit and count',  'description' => 'Measure objects using hand-widths, blocks, or footsteps and compare results. Non-standard measurement activities build the concept of measurement before the abstraction of centimetres — establishing that measurement is about iterating a unit and counting iterations, not about reading a scale.'],
            ['title' => 'Logical Reasoning Riddles',               'emoji' => '🧠', 'age_tier' => 'preschool', 'subject' => 'cognitive', 'age_min' => 4, 'age_max' => 5, 'is_free' => true,  'duration' => 10, 'activity_type' => 'game',        'skill' => 'Deductive reasoning from clues',      'description' => 'Solve age-appropriate riddles: "I have four legs, fur, and say woof. What am I?" Riddle-solving requires holding multiple constraints in working memory and reasoning to a point of intersection — deductive logic in its simplest accessible form for young children.'],
            ['title' => 'Estimation Jar: How Many Blocks?',        'emoji' => '🫙', 'age_tier' => 'preschool', 'subject' => 'cognitive', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'hands_on',    'skill' => 'Numerical estimation and benchmarking', 'description' => 'Estimate how many small blocks fill a jar, then count to check. Estimation exercises build numerical magnitude intuition — the approximate number sense that is a stronger predictor of later mathematics achievement than formal counting skill.'],

            // ═══════════════════════════════════════════════════════
            // ARABIC — batch 1 of 2 (activities 1–10)
            // ═══════════════════════════════════════════════════════
            ['title' => 'Arabic Alphabet Song: Alif to Ya',       'emoji' => '🔤', 'age_tier' => 'preschool', 'subject' => 'arabic', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 8,  'activity_type' => 'game',        'skill' => 'Arabic alphabet memorisation',         'description' => 'Sing the Arabic alphabet from alif (أ) to ya (ي) with a tune, pointing to each letter. Memorising the Arabic alphabet through a melodic song provides the foundational phonological mapping required for all subsequent Quranic reading, Arabic literacy, and Islamic textual study.'],
            ['title' => 'Tracing Arabic Letters in Sand',          'emoji' => '🔡', 'age_tier' => 'preschool', 'subject' => 'arabic', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Arabic letter formation, motor memory', 'description' => 'Trace Arabic letters right-to-left in a sand tray with one finger. Sand tracing activates kinesthetic motor-letter memory far more powerfully than pencil tracing — the tactile feedback of sand creates a multi-sensory encoding that dramatically accelerates letter retention.'],
            ['title' => 'Arabic Colour Words: Learn 5 Colours',    'emoji' => '🌈', 'age_tier' => 'preschool', 'subject' => 'arabic', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 10, 'activity_type' => 'game',        'skill' => 'Arabic vocabulary: colour words',      'description' => 'Learn five Arabic colour words — أحمر (red), أزرق (blue), أصفر (yellow), أخضر (green), أبيض (white) — matching flashcards to real objects. Vocabulary acquisition anchored to real objects is far more durable than picture-only flashcards; the physical touch-and-name method triples retention.'],
            ['title' => 'Matching Uppercase Arabic Letters',       'emoji' => '🅰️', 'age_tier' => 'preschool', 'subject' => 'arabic', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Arabic letter visual discrimination',  'description' => 'Match disconnected Arabic letter cards into identical pairs (baa-baa, taa-taa). Visual discrimination between Arabic letters — which share many stroke similarities — requires fine perceptual training; matching activities build the visual sensitivity required before reading can begin.'],
            ['title' => 'Arabic Body Parts: Raa\'s, Yad, Rijl',   'emoji' => '👋', 'age_tier' => 'preschool', 'subject' => 'arabic', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 8,  'activity_type' => 'game',        'skill' => 'Arabic vocabulary: body parts',        'description' => 'Learn Arabic body vocabulary — رأس (head), يد (hand), رجل (foot), عين (eye), أنف (nose) — via touch-and-say. Body-part vocabulary is the first and most universally useful Arabic vocabulary set: children interact with their own bodies constantly, providing thousands of daily repetition opportunities.'],
            ['title' => 'Arabic Number Words 1–10',                'emoji' => '🔢', 'age_tier' => 'preschool', 'subject' => 'arabic', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 10, 'activity_type' => 'game',        'skill' => 'Arabic number vocabulary',             'description' => 'Learn the Arabic names for 1–10 while counting physical objects: واحد، اثنان، ثلاثة، أربعة، خمسة، ستة، سبعة، ثمانية، تسعة، عشرة. Embedding Arabic number vocabulary in real counting contexts (not mere recitation) creates dual-language number sense rather than isolated memorisation.'],
            ['title' => 'Arabic Greetings and Phrases',            'emoji' => '👋', 'age_tier' => 'preschool', 'subject' => 'arabic', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 8,  'activity_type' => 'real_world',  'skill' => 'Arabic conversational phrases',        'description' => 'Practise Islamic Arabic greetings in context: السلام عليكم, الحمد لله, بسم الله, جزاك الله خيرا. Learning Arabic through Islamic formulaic phrases is the most efficient approach for Muslim households — these phrases are immediately usable, spiritually valuable, and constantly reinforced in daily religious practice.'],
            ['title' => 'Arabic Animal Names with Flashcards',     'emoji' => '🐘', 'age_tier' => 'preschool', 'subject' => 'arabic', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'game',        'skill' => 'Arabic vocabulary: animals',           'description' => 'Match picture flashcards to Arabic animal words: أسد (lion), قطة (cat), كلب (dog), فيل (elephant), سمكة (fish). Animal vocabulary is highly memorable due to emotional and visual salience; animal-name acquisition in Arabic provides a concrete, enjoyable bridge to broader Arabic language learning.'],
            ['title' => 'Pointing to Arabic Letters in a Book',   'emoji' => '📖', 'age_tier' => 'preschool', 'subject' => 'arabic', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Arabic print awareness',               'description' => 'Open any Arabic book and point to letters you recognise, reading right-to-left. Arabic print awareness — the understanding of directionality, letter-to-sound correspondence, and print tracking — must be established before formal reading instruction can succeed.'],
            ['title' => 'Arabic Letter Stamp Art',                 'emoji' => '🖋️', 'age_tier' => 'preschool', 'subject' => 'arabic', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'craft',       'skill' => 'Letter recognition through art',       'description' => 'Press foam Arabic letter stamps into ink and print them on paper, naming each one. Art-based letter exposure — stamping, printing, and naming — provides multi-sensory encoding (visual + tactile + auditory) that deepens letter memory far beyond worksheet practice.'],

            // ═══════════════════════════════════════════════════════
            // ARABIC — batch 2 of 2 (activities 11–25)
            // ═══════════════════════════════════════════════════════
            ['title' => 'Arabic Household Objects Labelling',     'emoji' => '🪑', 'age_tier' => 'preschool', 'subject' => 'arabic', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'real_world',  'skill' => 'Arabic vocabulary in the home environment', 'description' => 'Stick Arabic word labels on household objects — باب (door), كرسي (chair), طاولة (table), نافذة (window), كتاب (book). Environmental word labelling creates a total immersion microenvironment within the home; incidental repetition from passing these labels daily builds vocabulary without explicit study effort.'],
            ['title' => 'Arabic Listening to Simple Stories',      'emoji' => '🎧', 'age_tier' => 'preschool', 'subject' => 'arabic', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'game',        'skill' => 'Arabic listening comprehension',      'description' => 'Listen to a short, simple Arabic story with pictures and answer "What happened?" in any language. Comprehensible-input listening — a slightly above-level Arabic audio with picture support — is the evidence-based core of natural language acquisition for heritage languages.'],
            ['title' => 'Arabic Letter Beginning Sounds Sort',     'emoji' => '🔤', 'age_tier' => 'preschool', 'subject' => 'arabic', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Arabic phonemic awareness',            'description' => 'Sort picture cards by the Arabic letter they begin with (alif words, baa words, taa words). Phoneme-grapheme Arabic sorting — matching words to initial letters — is the pre-reading skill most directly predictive of Quran reading speed and accuracy in formal Qaida instruction.'],
            ['title' => 'Draw and Label in Arabic: My Family',    'emoji' => '👨‍👩‍👧', 'age_tier' => 'preschool', 'subject' => 'arabic', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'craft',       'skill' => 'Arabic family vocabulary + emergent writing', 'description' => 'Draw each family member and label them in Arabic: أبي (my father), أمي (my mother), أخي (my brother), أختي (my sister). Family-context vocabulary is emotionally salient and immediately reinforceable by family members in conversation — the ideal conditions for durable acquisition.'],
            ['title' => 'Arabic Simple Phrases: Please and Thank You', 'emoji' => '😊', 'age_tier' => 'preschool', 'subject' => 'arabic', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'real_world',  'skill' => 'Arabic social courtesy phrases',      'description' => 'Practise min fadlak (please), shukran (thank you), afwan (you\'re welcome), and la shukra ala wajib (thanks isn\'t necessary — it\'s a duty) in real daily interactions. Social routine phrases have the highest frequency and therefore fastest acquisition trajectory of all Arabic vocabulary.'],
            ['title' => 'Arabic Shapes Vocabulary',                'emoji' => '🔺', 'age_tier' => 'preschool', 'subject' => 'arabic', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'game',        'skill' => 'Arabic vocabulary: geometric shapes',  'description' => 'Learn shape words in Arabic while tracing each shape: دائرة (circle), مربع (square), مثلث (triangle), مستطيل (rectangle). Shape vocabulary review in Arabic doubles as geometric concept reinforcement — each word-learning session simultaneously consolidates shape recognition.'],
            ['title' => 'Sing a Simple Arabic Nasheed',            'emoji' => '🎵', 'age_tier' => 'preschool', 'subject' => 'arabic', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'game',        'skill' => 'Arabic phonemic exposure through song', 'description' => 'Learn a short, simple Arabic nasheed (a cappella only) and sing it repeatedly. Arabic nasheeds provide phonemic exposure to sounds difficult to replicate in standard English mouths (ع, خ, ح, ص) through melodic repetition — the most effective phonological training for heritage Arabic speakers.'],
            ['title' => 'Match Arabic Word to Picture',            'emoji' => '🃏', 'age_tier' => 'preschool', 'subject' => 'arabic', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Arabic word-picture linking',          'description' => 'Match printed Arabic vocabulary cards to corresponding picture cards. Word-to-picture matching establishes the critical direct link between graphemes (the printed word) and semantic concept (the picture) — bypassing translation through English and building genuine Arabic conceptual vocabulary.'],
            ['title' => 'Arabic Weather Words Discussion',          'emoji' => '⛅', 'age_tier' => 'preschool', 'subject' => 'arabic', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'real_world',  'skill' => 'Conversational Arabic: weather',      'description' => 'Every morning, describe the weather in Arabic: حار (hot), بارد (cold), ممطر (rainy), مشمس (sunny). Daily-life conversational routines — when practised in Arabic — create authentic communicative contexts that activate language acquisition even in non-immersion households.'],
            ['title' => 'Arabic Food Words at Mealtime',           'emoji' => '🍎', 'age_tier' => 'preschool', 'subject' => 'arabic', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'real_world',  'skill' => 'Arabic vocabulary: food and eating',   'description' => 'Name foods at mealtime in Arabic: ماء (water), خبز (bread), تفاحة (apple), أرز (rice), لبن (milk). Embedding Arabic vocabulary at mealtimes means the child hears and uses each food word hundreds of times per year — contextualised, meaningful, high-frequency repetition that is the foundation of fluency.'],
            ['title' => 'Trace My Name in Arabic',                 'emoji' => '✍️', 'age_tier' => 'preschool', 'subject' => 'arabic', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Arabic name writing, identity',       'description' => 'Trace, then try to write, your own name in Arabic letters. Learning to write one\'s name in Arabic script creates powerful identity connection to the language — a child who can write their name in Arabic feels ownership of Arabic as part of who they are, not merely a school subject.'],
            ['title' => 'Arabic Opposites: Big vs Small',          'emoji' => '↔️', 'age_tier' => 'preschool', 'subject' => 'arabic', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'game',        'skill' => 'Arabic vocabulary: opposites/adjectives', 'description' => 'Match opposite pairs in Arabic: كبير/صغير (big/small), طويل/قصير (tall/short), سريع/بطيء (fast/slow). Opposite-pair vocabulary acquisition is doubly efficient — each word learned pairs with its antonym, doubling vocabulary size; additionally, comparing opposites builds the semantic relationship categories needed for advanced comprehension.'],
            ['title' => 'Arabic Action Words: Move As I Say',      'emoji' => '🏃', 'age_tier' => 'preschool', 'subject' => 'arabic', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'game',        'skill' => 'Arabic verb vocabulary and TPR',      'description' => 'Call out Arabic action words and perform the action: اجلس (sit), قف (stand), اقفز (jump), الجري (run), توقف (stop). Total Physical Response (TPR) — responding physically to language commands — is the evidence-based L2 acquisition method for toddlers and preschoolers, requiring no translation or explanation.'],
            ['title' => 'Arabic Days of the Week Chant',           'emoji' => '📅', 'age_tier' => 'preschool', 'subject' => 'arabic', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'game',        'skill' => 'Arabic temporal vocabulary',           'description' => 'Chant the Arabic days of the week in sequence: الأحد، الاثنين، الثلاثاء، الأربعاء، الخميس، الجمعة، السبت. Days-of-week vocabulary is reinforced naturally every morning when the day is mentioned, making it one of the highest-frequency Arabic vocabulary sets available; Jumu\'ah (Friday) holds spiritual significance that deepens the learning.'],
            ['title' => 'Arabic Simple Sentence Construction',     'emoji' => '🗣️', 'age_tier' => 'preschool', 'subject' => 'arabic', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'game',        'skill' => 'Arabic sentence structure basics',    'description' => 'Build simple Arabic sentences using picture cards: "البيت كبير" (The house is big), "القطة نائمة" (The cat is sleeping). Constructing simple nominal sentences introduces the Arabic sentence pattern (noun + predicate) that differs from English (verb-before-subject in verbal sentences) — building grammatical intuition before formal grammar study.'],

            // ═══════════════════════════════════════════════════════
            // QURAN — batch 1 of 2 (activities 1–25)
            // is_muslim_only enforced at model layer — no DB flag needed
            // ═══════════════════════════════════════════════════════
            ['title' => 'Memorising Surah Al-Fatiha',             'emoji' => '📿', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Quran memorisation: Al-Fatiha',        'description' => 'Memorise Surah Al-Fatiha verse by verse, repeating after a clear reciter. Al-Fatiha, the opening chapter, is the most recited text in Islamic practice — recited 17 times per day in salah. Memorising it at preschool age establishes the first functional Quran vocabulary and enables the child to participate fully in family prayer.'],
            ['title' => 'Recognising the Arabic Letters in Quran', 'emoji' => '🔤', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Quranic letter recognition',           'description' => 'Point to individual letters in a large-print Mushaf and name them. Arabic letter recognition within actual Quranic text — not isolated flashcards — introduces the visual appearance of letters in connected script, the context in which the child will eventually read.'],
            ['title' => 'Learning Surah Al-Ikhlas',               'emoji' => '⭐', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 8,  'activity_type' => 'hands_on',    'skill' => 'Quran memorisation: Tawheed surah',    'description' => 'Memorise the four verses of Surah Al-Ikhlas (قُلْ هُوَ ٱللَّهُ أَحَدٌ...). Al-Ikhlas encapsulates the entire theology of Islamic monotheism in four verses — the Prophet ﷺ said it is equal in reward to a third of the Quran. It is the most important theological statement a Muslim child can memorise.'],
            ['title' => 'Learning Surah Al-Nas',                  'emoji' => '🌙', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 8,  'activity_type' => 'hands_on',    'skill' => 'Quran memorisation: protection surah', 'description' => 'Memorise Surah Al-Nas (قُلْ أَعُوذُ بِرَبِّ ٱلنَّاسِ). Al-Nas is the final surah of the Quran and a protection supplication. It is among the first surahs preschoolers learn and is used before sleep, teaching the child that turning to Allah for protection is a natural daily habit.'],
            ['title' => 'Learning Surah Al-Falaq',                'emoji' => '🌅', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 8,  'activity_type' => 'hands_on',    'skill' => 'Quran: al-Muawwidhatain',              'description' => 'Memorise Surah Al-Falaq (قُلْ أَعُوذُ بِرَبِّ ٱلْفَلَقِ). Together with Al-Nas, Al-Falaq forms Al-Muawwidhatain — the "two protections." The Prophet ﷺ recommended reciting these each morning and evening; establishing this habit at preschool age creates a lifelong protective devotional practice.'],
            ['title' => 'Learning the Meaning of Al-Fatiha',      'emoji' => '💬', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 12, 'activity_type' => 'hands_on',    'skill' => 'Quran comprehension: Al-Fatiha meaning', 'description' => 'Discuss the meaning of each verse of Al-Fatiha in simple words: "Praise is only for Allah; He is kind today and on Judgement Day..." Teaching meaning alongside memorisation prevents the Quran from becoming meaningless sound production and builds an early theological understanding of Allah\'s attributes.'],
            ['title' => 'Listening to the Quran Recitation Daily', 'emoji' => '🎧', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 10, 'activity_type' => 'real_world',  'skill' => 'Quran phonemic exposure and love',     'description' => 'Listen to a clear, melodic Quran recitation for 10 minutes during a calm activity. Regular passive listening to Quranic recitation — even before active memorisation — builds phonemic exposure to the exact sounds and melody of the Quran, making future memorisation dramatically faster and more accurate.'],
            ['title' => 'Memorising Ayat Al-Kursi',               'emoji' => '🕌', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'hands_on',    'skill' => 'Quran memorisation: greatest verse',  'description' => 'Begin memorising Ayat Al-Kursi (Verse 255 of Surah Al-Baqarah) in short phrases. The Prophet ﷺ described Ayat Al-Kursi as the greatest verse in the Quran — it enumerates Allah\'s attributes of absolute sovereignty and watchfulness. Children who memorise it early carry the theologically richest single verse of the Quran with them always.'],
            ['title' => 'Learning the Alphabet of the Quran (Qaida)', 'emoji' => '📚', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'hands_on',    'skill' => 'Quranic reading readiness (Qaida)',    'description' => 'Using the Noorani Qaida or Al-Qaida Noorania, practise the isolated letters with their correct Quranic pronunciation. The Qaida method teaches the precise Tajweed articulation points (makhaarij) for each letter from the start — preventing the compensatory mispronunciations that are extremely difficult to correct after habits form.'],
            ['title' => 'Surah Al-Kawthar: Memory and Meaning',   'emoji' => '💧', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'hands_on',    'skill' => 'Quran: shortest three-verse surah',   'description' => 'Memorise Surah Al-Kawthar (إِنَّا أَعْطَيْنَٰكَ ٱلْكَوْثَرَ...) and learn it means "Surely We gave you the abundance" — and that this was revealed as comfort to the Prophet ﷺ. Even at preschool, connecting a surah to its context of revelation begins the child\'s relationship with the Quran as living guidance, not merely chanted syllables.'],
            ['title' => 'Surah Al-Masad: Memorisation',           'emoji' => '🔥', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'hands_on',    'skill' => 'Quran memorisation: Juz Amma',         'description' => 'Memorise Surah Al-Masad (تَبَّتْ يَدَا أَبِى لَهَبٍ) with correct pronunciation. Al-Masad is short and phonetically distinctive; it also provides a first Seerah connection — the child learns that even opposition to the Prophet ﷺ is recorded in the Quran as a historical and theological lesson.'],
            ['title' => 'Surah Al-Nasr: Memory and Context',      'emoji' => '🌟', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'hands_on',    'skill' => 'Quran: victory and gratitude themes',  'description' => 'Memorise Surah Al-Nasr (إِذَا جَاءَ نَصْرُ ٱللَّهِ وَٱلْفَتْحُ) and learn it was revealed after the conquest of Makkah. Al-Nasr introduces the concept of divine victory and the response to it — gratitude and seeking forgiveness — a foundational Islamic lesson about the purpose of all success.'],
            ['title' => 'Surah Al-Kafirun: Identity Lesson',      'emoji' => '✋', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Quran: religious identity and boundaries', 'description' => 'Memorise Surah Al-Kafirun (قُلْ يَٰٓأَيُّهَا ٱلْكَٰفِرُونَ) and learn it means "Say: O you who reject faith — your way is yours and my way is mine." Al-Kafirun establishes peaceful but firm religious identity — one of the most practically important concepts for Muslim children growing up in pluralistic societies.'],
            ['title' => 'Surah Al-Fil: Story of the Elephants',   'emoji' => '🐘', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Quran: divine protection narrative',  'description' => 'Memorise Surah Al-Fil (أَلَمْ تَرَ كَيْفَ فَعَلَ رَبُّكَ بِأَصْحَٰبِ ٱلْفِيلِ?) and hear the story of the elephants sent to destroy the Kaaba. Narrative surahs like Al-Fil connect Quran memorisation to vivid historical events — children who know the story behind a surah memorise it with dramatically greater retention and emotional connection.'],
            ['title' => 'Surah Quraysh: Gratitude for Blessings', 'emoji' => '🕋', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'hands_on',    'skill' => 'Quran memorisation + gratitude lesson', 'description' => 'Memorise Surah Quraysh (لِإِيلَٰفِ قُرَيْشٍ) and understand it thanks Allah for the security of food and travel. Al-Quraysh explicitly names the blessings of food and safety as divine gifts — making it an ideal surah to memorise alongside gratitude character work.'],
            ['title' => 'Surah Al-Maun: Helping the Needy',       'emoji' => '🤲', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Quran: social responsibility lesson',  'description' => 'Memorise Surah Al-Maun (أَرَءَيْتَ ٱلَّذِى يُكَذِّبُ بِٱلدِّينِ?) and learn it criticises those who neglect orphans and the needy. Al-Maun directly connects Quran to ethics of social responsibility — introducing the child to the concept that Islamic practice includes caring for the vulnerable, not only ritual worship.'],
            ['title' => 'Tajweed: Learning to Say ع and ح Correctly', 'emoji' => '🗣️', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Tajweed articulation: throat letters',  'description' => 'Practise the correct pronunciation of ع (ayn) and ح (ha) using physical articulation exercises. The pharyngeal consonants ع and ح are absent from English phonology; establishing correct articulation by age 5 — before the critical phonological acquisition window closes — prevents the ingrained mispronunciations common among English-first Muslim children.'],
            ['title' => 'Surah Az-Zalzalah: The Earthquake',      'emoji' => '🌍', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Quran: accountability and Akhirah',   'description' => 'Begin memorising Surah Az-Zalzalah (إِذَا زُلْزِلَتِ ٱلْأَرْضُ زِلْزَالَهَا) and learn it describes the earth shaking on the Day of Judgement. Az-Zalzalah introduces the concept of Akhirah (the hereafter) and divine accountability in child-appropriate terms — every atom of good and evil matters to Allah.'],
            ['title' => 'Surah Al-Adiyat: Running Horses Imagery', 'emoji' => '🐎', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Quran: ingratitude warning lesson',   'description' => 'Memorise Surah Al-Adiyat (وَٱلْعَٰدِيَٰتِ ضَبْحًا) and hear the vivid imagery of galloping war horses. Al-Adiyat uses powerful sensory imagery — the sound and fire of running horses — to engage the imagination before delivering its moral lesson about human ingratitude. Imagery-rich surahs are easier to memorise and create stronger neural encodings.'],
            ['title' => 'Surah Al-Qaria: The Day of Judgement',   'emoji' => '⚖️', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Quran: scales of deeds concept',      'description' => 'Begin memorising Surah Al-Qaria (ٱلْقَارِعَةُ مَا ٱلْقَارِعَةُ?) and learn about the scales that weigh deeds. Al-Qaria introduces the concept of the mizan (scale) of deeds in child-accessible imagery — "a moth-scattered people" and "carded wool" — making abstract eschatology tangible.'],
            ['title' => 'Recitation with Correct Posture',         'emoji' => '🧎', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'real_world',  'skill' => 'Quran etiquette: wudu, posture, reverence', 'description' => 'Before reading, make wudu, sit up straight, face the qibla if possible, and open the Mushaf with "bismillah." Quran adab (etiquette) — the physical reverence of preparation, posture, and bismillah — communicates to a child through behaviour what the intellect cannot yet fully grasp: that this is sacred and different from any other reading.'],
            ['title' => 'Surah Al-Takathur: Warning Against Competition', 'emoji' => '🏆', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Quran: materialism warning lesson',   'description' => 'Begin memorising Surah Al-Takathur (أَلْهَىٰكُمُ ٱلتَّكَاثُرُ) and learn it warns against being distracted by competing in accumulating possessions. Al-Takathur is one of the most direct Quranic warnings against materialism — a foundational counter-cultural lesson for children in consumer societies.'],
            ['title' => 'Surah Al-Asr: The Key Formula',           'emoji' => '⏰', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'hands_on',    'skill' => 'Quran: formula for life success',     'description' => 'Memorise Surah Al-Asr (وَٱلْعَصْرِ إِنَّ ٱلْإِنسَٰنَ لَفِى خُسْرٍ) and understand it is three verses containing the formula for human success: faith, righteous deeds, truth, and patience. Imam Ash-Shafi\'i said that if people pondered only this surah, it would be sufficient for them — it is the Quran\'s complete prescription for a good life in miniature.'],
            ['title' => 'Surah Al-Humazah: Backbiting Warning',   'emoji' => '👁️', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'hands_on',    'skill' => 'Quran: social ethics lesson',          'description' => 'Memorise Surah Al-Humazah (وَيْلٌ لِّكُلِّ هُمَزَةٍ لُّمَزَةٍ) and learn it condemns mockery, backbiting, and pride in wealth. Al-Humazah directly prohibits three social vices — mocking others, backbiting, and boasting about possessions — making it the ideal Quran companion to the social-character curriculum.'],
            ['title' => 'Daily Quran Review: 3-Surahs Before Bed', 'emoji' => '🌙', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'real_world',  'skill' => 'Quran habit: daily memorisation review', 'description' => 'Recite three previously memorised surahs from memory every evening before bed. Spaced repetition of memorised Quran — returning to surahs daily, then every few days, then weekly — is the mechanism by which short-term memorisation becomes permanent hifz. The pre-sleep timing also exploits the brain\'s memory consolidation during early sleep.'],

            // ═══════════════════════════════════════════════════════
            // QURAN — batch 2 of 2 (activities 26–35)
            // ═══════════════════════════════════════════════════════
            ['title' => 'Surah Al-Feel: Revision and Drawing',    'emoji' => '🐘', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'craft',       'skill' => 'Quran narrative recall and illustration', 'description' => 'Recite Surah Al-Fil from memory, then draw the army of elephants and the birds. Combining Quran recitation with visual representation deepens narrative comprehension and creates multi-sensory memory anchors — the child\'s drawing becomes a personal mnemonic connected to the surah forever.'],
            ['title' => 'Practising Basmalah Before Everything',  'emoji' => '🌸', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 5,  'activity_type' => 'real_world',  'skill' => 'Quran habit: bismillah as constant practice', 'description' => 'Practise saying بسم الله (Bismillah) before every action: eating, drinking, reading, getting dressed, leaving home. The Prophet ﷺ taught that any significant action not begun with Bismillah is "cut off" from blessing. Establishing this habit at preschool age means the child internalises divine consciousness as the natural starting point for all purposeful action.'],
            ['title' => 'Surah Ad-Duha: Comfort of the Prophet',  'emoji' => '☀️', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Quran: divine reassurance lesson',     'description' => 'Memorise the first three verses of Surah Ad-Duha and learn Allah revealed them to reassure the Prophet ﷺ when he felt abandoned. Children who experience moments of sadness or loneliness gain profound comfort from learning that even the Prophet ﷺ needed reassurance — and that Allah never abandons those who love Him.'],
            ['title' => 'Surah Al-Inshirah: Ease With Hardship',  'emoji' => '💪', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'hands_on',    'skill' => 'Quran: resilience theology',           'description' => 'Memorise Surah Al-Inshirah (أَلَمْ نَشْرَحْ لَكَ صَدْرَكَ?) and learn its central promise: "With every hardship comes ease." The repeated promise of ease with difficulty — stated twice in the same surah — gives children a theological anchor for resilience: difficulty is never permanent, and Allah has purpose in every struggle.'],
            ['title' => 'Practising Taawwudh Before Recitation',  'emoji' => '🛡️', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 5,  'activity_type' => 'real_world',  'skill' => 'Quran etiquette: Aoudhu Billah',       'description' => 'Memorise and always say أعوذ بالله من الشيطان الرجيم (I seek refuge in Allah from Satan) before beginning recitation. The taawwudh before recitation is commanded in the Quran (16:98) — teaching a child this reflex establishes the Quranic practice of seeking divine protection before sacred speech.'],
            ['title' => 'Surah Al-Tin: Three Sacred Lands',       'emoji' => '🌿', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Quran: human dignity and creation',   'description' => 'Begin memorising Surah At-Tin (وَٱلتِّينِ وَٱلزَّيْتُونِ) and learn that Allah created humans in "the best of forms." At-Tin establishes the Islamic concept of human dignity — that humans are honoured creations (Ashraf al-Makhluqat) — a theological foundation for both self-worth and respect for others.'],
            ['title' => 'Surah Al-Alaq: First Revelation',        'emoji' => '📖', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Quran: first revelation story + reading', 'description' => 'Learn the first five verses of Surah Al-Alaq (ٱقْرَأْ بِٱسْمِ رَبِّكَ ٱلَّذِى خَلَقَ) and hear the story of the first Quranic revelation. Al-Alaq\'s first command is "Read" — introducing the child to the Islamic concept that knowledge through reading is a divine command, establishing a lifelong Islamic motivation for literacy.'],
            ['title' => 'Weekly Hifz Review Session',              'emoji' => '🔄', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'hands_on',    'skill' => 'Quran retention through spaced review', 'description' => 'Recite all memorised surahs from beginning to end once per week in a structured family session. Consolidation review prevents the "forgetting curve" — research shows that memorised material without spaced review is 80% lost within 30 days; weekly whole-hifz review maintains near-100% retention indefinitely.'],
            ['title' => 'Surah Al-Qadr: Night of Power',          'emoji' => '✨', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'hands_on',    'skill' => 'Quran: Laylat al-Qadr lesson',         'description' => 'Memorise Surah Al-Qadr (إِنَّا أَنزَلْنَٰهُ فِى لَيْلَةِ ٱلْقَدْرِ) and learn about the Night of Power when the Quran was sent down. Al-Qadr introduces children to the primacy of the Quran itself as a gift from Allah on the most blessed night — creating a cyclical connection between the text they are memorising and its sacred origin.'],
            ['title' => 'Performing a Mini Quran Exhibition',      'emoji' => '🎤', 'age_tier' => 'preschool', 'subject' => 'quran', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 15, 'activity_type' => 'real_world',  'skill' => 'Quran: confidence in public recitation', 'description' => 'Perform all memorised surahs for a family gathering, reciting each one clearly from memory. Public recitation before a loving, supportive audience creates the experience of Quran as a gift to be shared — building the haafidh\'s identity as someone who carries and presents the Book of Allah — not merely a private memoriser.'],

            // ═══════════════════════════════════════════════════════
            // ISLAMIC STUDIES — batch 1 of 2 (activities 1–15)
            // ═══════════════════════════════════════════════════════
            ['title' => 'The 5 Pillars: A Rhyme for Young Muslims', 'emoji' => '🕌', 'age_tier' => 'preschool', 'subject' => 'islamic_studies', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 8,  'activity_type' => 'game',        'skill' => 'Five Pillars: foundational Islamic structure', 'description' => 'Learn the Five Pillars of Islam through a rhyme: Shahada, Salah, Zakat, Sawm, Hajj — counting on five fingers. The Five Pillars provide the organising framework of Islamic practice; memorising their names and sequence by age 4 gives children the schema into which all subsequent Islamic knowledge is effortlessly filed.'],
            ['title' => 'Learning the Shahada: Meaning and Use',   'emoji' => '☝️', 'age_tier' => 'preschool', 'subject' => 'islamic_studies', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 10, 'activity_type' => 'hands_on',    'skill' => 'Shahada: tawheed and risalah',         'description' => 'Memorise and understand the Shahada: "Laa Ilaaha Illallah, Muhammadun Rasulullah" — "There is no god except Allah; Muhammad ﷺ is His Messenger." The Shahada is the first word spoken into a newborn\'s ear in Islam; understanding it at preschool age establishes the theological foundation from which all Islamic life and ethics flow.'],
            ['title' => 'Salah Movements: Learning to Pray',       'emoji' => '🧎', 'age_tier' => 'preschool', 'subject' => 'islamic_studies', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 15, 'activity_type' => 'real_world',  'skill' => 'Salah: physical positions and sequence', 'description' => 'Practise the physical positions of salah — qiyam (standing), ruku (bowing), sujood (prostration), juloos (sitting) — alongside an adult. The Prophet ﷺ said "Pray as you have seen me pray." Children who learn the physical movements early develop proprioceptive "muscle memory" for salah that makes the prayer feel natural rather than effortful throughout life.'],
            ['title' => 'Allah\'s Names: Ar-Rahman and Ar-Rahim',  'emoji' => '💛', 'age_tier' => 'preschool', 'subject' => 'islamic_studies', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 10, 'activity_type' => 'game',        'skill' => 'Asma ul-Husna: mercy attributes',     'description' => 'Learn the meaning of Ar-Rahman (The Most Merciful) and Ar-Rahim (The Especially Merciful) with examples: "Allah gives rain for plants because He is Ar-Rahman." Beginning with Allah\'s attributes of mercy — not primarily fear and punishment — establishes the theologically correct foundation: Islam\'s first relationship with Allah is love and mercy, not dread.'],
            ['title' => 'The Story of Adam and Eve (Simplified)',  'emoji' => '🌳', 'age_tier' => 'preschool', 'subject' => 'islamic_studies', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 12, 'activity_type' => 'game',        'skill' => 'Aqidah: creation and human origin',   'description' => 'Hear the story of Adam and Hawwa — the first humans, created by Allah, and taught the names of all things. The story of Adam introduces children to their own origin in divine creation, the concept of Jannah (paradise), and the Islamic understanding that humans are inherently good but need divine guidance.'],
            ['title' => 'Making Wudu: The Order of Steps',         'emoji' => '💧', 'age_tier' => 'preschool', 'subject' => 'islamic_studies', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 10, 'activity_type' => 'real_world',  'skill' => 'Wudu: purification ritual sequence',  'description' => 'Practise making wudu in the correct order: intention, bismillah, hands, mouth, nose, face, right arm, left arm, head, ears, feet. Wudu is performed 5+ times daily — practising the sequence until it is automatic at preschool age means the child approaches salah ready, without cognitive load spent on remembering steps.'],
            ['title' => 'The Prophet\'s Love for Children',        'emoji' => '❤️', 'age_tier' => 'preschool', 'subject' => 'islamic_studies', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 10, 'activity_type' => 'game',        'skill' => 'Seerah: the Prophet ﷺ as role model',  'description' => 'Hear stories of how the Prophet Muhammad ﷺ loved children — carrying Al-Hasan on his shoulders during prayer, playing with grandchildren, never scolding children for interrupting. Children who learn the Prophet\'s gentleness toward children develop a personal, loving relationship with him ﷺ rather than a distant, fearful one.'],
            ['title' => 'Angels: What Are They and What Do They Do?', 'emoji' => '👼', 'age_tier' => 'preschool', 'subject' => 'islamic_studies', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 10, 'activity_type' => 'game',        'skill' => 'Aqidah: belief in angels',             'description' => 'Learn that Allah created angels from light, they have no free will, and Jibril brought revelation and Mikail brings rain. Belief in angels (Iman bil-Malaika) is the second of the Six Pillars of Iman; learning their roles makes the concept concrete rather than purely abstract for young children.'],
            ['title' => 'Halal and Haram: Making Good Choices',    'emoji' => '✅', 'age_tier' => 'preschool', 'subject' => 'islamic_studies', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'game',        'skill' => 'Islamic ethics: halal/haram framework', 'description' => 'Sort picture cards into halal (allowed) and haram (not allowed) food and behaviour categories with clear explanations of why. Introducing the halal/haram framework at preschool age creates an Islamic ethical lens before the child is old enough to receive peer pressure — the concept becomes a natural part of decision-making rather than an imposed external rule.'],
            ['title' => 'Saying Alhamdulillah for Everything',     'emoji' => '🙏', 'age_tier' => 'preschool', 'subject' => 'islamic_studies', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 8,  'activity_type' => 'real_world',  'skill' => 'Dhikr habit: Alhamdulillah always',   'description' => 'Practise saying الحمد لله (Alhamdulillah — All praise is for Allah) after every good thing and every meal. The Prophetic teaching is that gratitude expressed to Allah is itself a form of worship; building the Alhamdulillah reflex means the child develops a constant background awareness of divine blessing in everyday life.'],
            ['title' => 'The Qibla: Which Direction Do We Face?',  'emoji' => '🧭', 'age_tier' => 'preschool', 'subject' => 'islamic_studies', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 8,  'activity_type' => 'real_world',  'skill' => 'Qibla awareness and unity of Muslims',  'description' => 'Using a compass or app, find the qibla direction and explain that all Muslims worldwide face the same direction to pray. Understanding the qibla introduces both spatial reasoning (directions) and the profound concept of Muslim unity — millions of people worldwide all facing one point together simultaneously.'],
            ['title' => 'Seerah Story: Birth of the Prophet ﷺ',    'emoji' => '🌙', 'age_tier' => 'preschool', 'subject' => 'islamic_studies', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'game',        'skill' => 'Seerah: Prophet\'s birth and early life', 'description' => 'Hear the story of the Prophet Muhammad\'s birth in Makkah in the Year of the Elephant. Beginning the Seerah at preschool age with the birth story — a positive, wondrous narrative — establishes emotional connection and love for the Prophet ﷺ as the starting point, before doctrinal or legal content.'],
            ['title' => 'Learning About Jannah: Allah\'s Garden',  'emoji' => '🌸', 'age_tier' => 'preschool', 'subject' => 'islamic_studies', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'game',        'skill' => 'Aqidah: Jannah and motivation for good', 'description' => 'Learn about Jannah — that it has rivers of milk, honey, and water; beautiful palaces; and everyone there is happy forever. Teaching Jannah through vivid sensory description (a Quranic approach) creates the positive motivational goal at the heart of Islamic practice: goodness is rewarded with infinite beauty.'],
            ['title' => 'Sadaqah: Giving to Those in Need',        'emoji' => '💰', 'age_tier' => 'preschool', 'subject' => 'islamic_studies', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 10, 'activity_type' => 'real_world',  'skill' => 'Islamic charity: concept and practice', 'description' => 'Put a small coin in a sadaqah box and discuss who it will help and why giving is beloved by Allah. Physical sadaqah practice at preschool age creates embodied generosity — the motor action of releasing a coin into a charity box encodes giving as a habit of the body as well as a value of the mind.'],
            ['title' => 'Dua Before Eating and After',             'emoji' => '🍽️', 'age_tier' => 'preschool', 'subject' => 'islamic_studies', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 5,  'activity_type' => 'real_world',  'skill' => 'Islamic daily habits: mealtime duas',  'description' => 'Memorise the eating dua (Bismillah before, Alhamdulillah after) and practise it at every meal. Mealtime duas are among the highest-frequency Islamic practices in a child\'s day — practised 3+ times daily, they accumulate thousands of repetitions per year, making gratitude-toward-Allah the default cognitive state around food.'],

            // ═══════════════════════════════════════════════════════
            // ISLAMIC STUDIES — batch 2 of 2 (activities 16–25)
            // ═══════════════════════════════════════════════════════
            ['title' => 'Allah is Al-Khaliq: He Created Everything', 'emoji' => '🌍', 'age_tier' => 'preschool', 'subject' => 'islamic_studies', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 10, 'activity_type' => 'outdoor',     'skill' => 'Tawheed: Allah as Creator (Al-Khaliq)', 'description' => 'Go outside, point to things (sky, trees, ant, cloud) and say "Allah made this." Connecting the Name Al-Khaliq to direct observation of creation grounds the concept in immediate sensory experience — the child sees with their own eyes the evidence for divine creation rather than accepting it as abstract doctrine.'],
            ['title' => 'Saying Mashallah When Admiring Something', 'emoji' => '😍', 'age_tier' => 'preschool', 'subject' => 'islamic_studies', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 5,  'activity_type' => 'real_world',  'skill' => 'Islamic phrase: Mashallah (attribution)', 'description' => 'Practise saying "Mashallah" when something beautiful or impressive is seen. Mashallah ("Allah has willed it") attributes all goodness and beauty to Allah — developing habitual divine attribution; it also carries protective significance, countering the concept of the Evil Eye (hasad) as understood in Islamic tradition.'],
            ['title' => 'Dua for Entering and Leaving the Home',   'emoji' => '🚪', 'age_tier' => 'preschool', 'subject' => 'islamic_studies', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 8,  'activity_type' => 'real_world',  'skill' => 'Islamic daily habits: home entry/exit duas', 'description' => 'Learn and practise the dua for leaving home (بسم الله توكلت على الله) and entering home. These prophetic duas are practised multiple times daily — establishing the Islamic concept that every transition — leaving, entering, sleeping, waking — is accompanied by divine consciousness and seeking of protection.'],
            ['title' => 'Prophet Nuh (Noah) Story: Patience and Dawah', 'emoji' => '🚢', 'age_tier' => 'preschool', 'subject' => 'islamic_studies', 'age_min' => 3, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'game',        'skill' => 'Seerah al-Anbiya: patience and steadfastness', 'description' => 'Hear the story of Prophet Nuh — 950 years of calling people to Allah, building the ark, and the great flood. Prophet Nuh\'s story teaches the most important character lesson in the Quran — extraordinary patience and perseverance in difficult circumstances — through a narrative so vivid and dramatic that children never forget it.'],
            ['title' => 'Prophet Ibrahim: Breaking the Idols',      'emoji' => '🗿', 'age_tier' => 'preschool', 'subject' => 'islamic_studies', 'age_min' => 4, 'age_max' => 5, 'is_free' => false, 'duration' => 12, 'activity_type' => 'game',        'skill' => 'Tawheed via Seerah: Ibrahim and idolatry', 'description' => 'Hear the story of Prophet Ibrahim breaking the idols and standing firm before the king. Ibrahim\'s courage in confronting idol-worship provides children with their first Quranic example of tawheed in action — and his logical argument (who broke the idols? ask the biggest one) introduces the concept of rational proof for Allah\'s oneness.'],
            ['title' => 'Learning the Takbir: Allahu Akbar',        'emoji' => '🔊', 'age_tier' => 'preschool', 'subject' => 'islamic_studies', 'age_min' => 3, 'age_max' => 5, 'is_free' => true,  'duration' => 8,  'activity_type' => 'real_world',  'skill' => 'Dhikr: Allahu Akbar and its meaning',  'description' => 'Learn to say الله أكبر (Allahu Akbar — Allah is the Greatest) and understand it means nothing is bigger or more important than Allah. Allahu Akbar is the most frequently declared phrase in Islamic practice, beginning salah, the Adhan, supplication, and moments of awe — internalising its meaning establishes a life-orienting priority: Allah above all else.'],
